/**
 * seed-conteudo.ts — GERADO por scripts/gen_seed_d.mjs (V23.5, D.1 + D.4).
 * Mini-ensino didatico + versiculo-chave por licao. NAO editar a mao.
 * Total: 220 licoes.
 */
import type { SQLiteDatabase } from 'expo-sqlite';

// [licao_id, explicacao, versiculo_chave]
export const CONTEUDO_LICOES: Array<[string, string, string]> = [
  ['FB01-L05', 'A Bíblia é um livro especial que contém muitos livros reunidos. Podemos organizar esses livros em grupos para facilitar nosso estudo. A classificação mais importante divide a Bíblia em duas grandes partes: o Antigo Testamento, que conta a história antes da vinda de Jesus, e o Novo Testamento, que fala sobre a vida de Jesus e o início da Igreja. Essa organização nos ajuda a entender melhor cada história e ensinamento da Palavra de Deus.', 'Lucas 24:44'],
  ['FB01-L06', 'A Biblia e dividida em dois grandes blocos: o Antigo Testamento, com 39 livros, e o Novo Testamento, com 27 livros, totalizando 66 livros. Para localizar um livro, primeiro identifique se ele pertence ao Antigo ou ao Novo Testamento e depois procure seu nome no indice da Biblia. Os livros estao organizados por ordem alfabetica dentro de seus blocos, o que facilita a busca. Com pratica, voce consegue encontrar qualquer livro rapidamente!', '2 Timoteo 3:16'],
  ['FB01-L01', 'A Bíblia é o livro mais especial que existe, porque é a própria Palavra de Deus escrita para nós. Ela foi escrita por muitas pessoas diferentes, ao longo de muitos anos, mas todas foram guiadas pelo Espírito Santo de Deus. A Bíblia nos ensina sobre o amor de Deus, sobre como Ele quer que vivamos, e nos mostra o caminho para termos uma vida com propósito e esperança.', '2 Timoteo 3:16'],
  ['FB01-L08', 'A Bíblia é cheia de histórias escritas por Deus para nos ensinar. Cada personagem bíblico - como Abraão, Moisés, Davi, Maria e muitos outros - tem uma história especial que nos mostra como Deus age na vida das pessoas. Quando conhecemos esses personagens, entendemos melhor os planos de Deus para nós e aprendemos lições valiosas para a nossa própria vida de fé.', 'Hebreus 11:1-2'],
  ['FB01-L07', 'A Biblia e um livro muito especial que possui uma organizacao muito pratica para nos ajudar a encontrar qualquer texto. Ela e dividida em livros, que sao divididos em capitulos, e cada capitulo e dividido em versiculos. Quando aprendemos a ler uma referencia biblica, como Joao 3:16, fica facil descobrir exatamente ondeestao as palavras de Deus. Comeca pedindo a Deus que te ajude a conhecer cada vez mais a Sua Palavra.', 'Salmos 119:105'],
  ['FB01-L02', 'A Biblia e como um grande livro que tem duas partes principais. A primeira parte e o Antigo Testamento, que conta a historia do povo de Deus desde a criacao do mundo ate os tempos antes de Jesus. A segunda parte e o Novo Testamento, que conta a historia de Jesus e como a igreja comecou. Juntos, os dois testamentos nos mostram o plano de amor de Deus para nos.', 'Hebreus 1:1-2'],
  ['FB01-L09', 'A Biblia nos conta a historia de Deus agindo em lugares especiais para nos abençoar. Lugares como Belém, onde Jesus nasceu, Jerusalem, onde ficava o Templo, e Getsêmani, onde Jesus orou, sao muito importantes porque nos ajudam a entender melhor a historia da salvacao. Conhecer esses lugares torna nossa leitura da Biblia mais rica e nos aproxima das historias que Deus quer nos ensinar.', 'Salmos 122:1-2'],
  ['FB01-L03', 'A Bíblia é um livro especial formado por 66 outros livros, escritos por muitas pessoas ao longo de mais de mil anos, mas todos inspirados por Deus. Ela é dividida em duas grandes partes: o Antigo Testamento, com 39 livros, e o Novo Testamento, com 27 livros. Cada livro está colocado numa ordem específica que nos ajuda a entender a história da Salvação desde a criação do mundo até a promessa da volta de Jesus.', 'Salmos 119:89'],
  ['FB02-L01', 'A Bíblia não é apenas um livro de regras ou histórias antigas. Ela é a história do amor de Deus por nós! Desde o início, quando o ser humano se afastou de Deus por causa do pecado, Deus já tinha um plano marvelous para nos resgatar. Esse plano se cumpriu quando Jesus veio ao mundo, morreu na cruz e ressuscitou para que todo aquele que acredita Nele pudesse ter vida eterna e uma relação verdadeira com o Pai. A mensagem central da Bíblia é: Deus nos ama tanto que enviou Jesus para nos salvar!', 'Joao 3:16'],
  ['FB02-L02', 'Deus criou o ser humano com muito amor e cuidado, dando-lhe um propósito muito especial. Nós fomos criados à imagem e semelhança de Deus, o que significa que temos capacidade de amar, de conhecer a Deus e de refletir o Seu caráter. O nosso propósito principal é ter um relacionamento profundo com o nosso Criador e cuidar de tudo aquilo que Ele nos confiou. Quando entendemos isso, percebemos que cada dia da nossa vida tem um significado divino.', 'Genesis 1:27'],
  ['FB01-L10', 'A Bíblia nos apresenta diversos povos que tiveram papéis importantes na história da salvação. Os hebreus, descendentes de Abraão, foram o povo escolhido por Deus para revelar Seus planos. Mas outros povos, como os egípcios, babilônios, gregos e romanos, também aparecem na Bíblia e cumpriram purposes especiais no caminho de Deus para a humanidade. Conhecer esses povos nos ajuda a entender melhor o contexto das histórias bíblicas e como Deus trabalha com pessoas de diferentes culturas e nações.', 'Atos 10:34-35'],
  ['FB01-L12', 'A Bíblia é um livro muito especial que tem 66 livros no total, organizados numa ordem que Deus permitiu que fosse assim. Quando a gente memoriza a ordem dos livros, fica mais fácil encontrar as histórias e ensinamentos que precisamos. Começando pelos livros que contam a criação e a história do povo de Deus, depois os livros de ensinamento, e por fim os livros que falam sobre o fim dos tempos. Com a ajuda do Espírito Santo, podemos guardar essa ordem no nosso coração e usar a Bíblia com mais confiança!', 'Salmo 119:11'],
  ['FB01-L11', 'Deus escolheu pessoas comuns, como pescadores, médicos e reis, para escrever os livros da Bíblia. Cada autor escreveu em seu próprio estilo, mas a mensagem vinha de Deus. Assim, a Bíblia não é apenas um livro humano, mas a palavra de Deus registrada por mãos humanas.', '2 Timóteo 3:16'],
  ['FB02-L04', 'Depois do Dilúvio, Deus fez uma promessa especial a Noé e a toda a criação. Com o tempo, as famílias cresceram e se espalharam pela terra. Mas as pessoas decidiram construir uma cidade com uma torre muito alta para fazer nome para si mesmas, em vez de obedeccer a Deus. Isso desagradou a Deus, que confundiu as línguas e espalhou as nações pelo mundo.', 'Genesis 11:9'],
  ['FB02-L09', 'Depois do rei Salomão, o povo de Israel se dividiu em dois reinos. O Reino do Norte ficou chamado de Israel, com dez tribos, e o Reino do Sul ficou chamado de Judá, com duas tribos. Essa separação aconteceu porque o povo não quis mais seguir um só rei, e isso trouxe muitas consequências para a história do povo de Deus.', '1 Reis 12:19'],
  ['FB02-L05', 'Os patriarcas de Israel foram homens escolhidos por Deus para serem os avós e pais do povo israelita. Abraão foi o primeiro patriarca, chamado por Deus para sair de sua terra e seguir em direção à terra que Deus lhe mostraria. Depois dele veio Isaque, seu filho, e depois Jacó, neto de Abraão. Jacó recebeu o nome de Israel depois de lutar com um anjo. Deus fez grandes promessas a esses homens, e através deles começou a formar uma grande nação. Eles são muito importantes porque mostram como Deus cumpre suas promessas e como podemos confiar nele, mesmo quando não entendemos todos os caminhos que ele nos leva.', 'Genesis 28:14'],
  ['FB01-L04', 'Assim como temos nomes completos e apelidos, a Biblia tambem tem! As abreviacoes sao formas resumidas de escrever os nomes dos livros biblicos. Quando看到一个 texto ou um devocional, voce vera Mt para Mateus, Pv para Proverbios, Sl para Salmos e assim por diante. Aprender essas abreviacoes ajuda voce a encontrar os versiculos mais depressa e a entender melhor os estudos biblicos que usar essas formas curtas. Com a pratica, voce vai reconhecer cada abreviacao naturalmente, do mesmo jeito que reconhece seus amigos pelo nome.', 'Salmos 119:105'],
  ['FB02-L07', 'Depois de quarenta anos no deserto, Deus cumpriu sua promessa e levou o povo de Israel para a Terra Prometida. Josué, o novo líder escolhido por Deus, orientou o povo a ser forte e corajoso, porque Deus lutaria por eles. Com a queda de Jericó e outras vitórias, as tribos de Israel tomaram posse das terras que Deus havia preparado para elas. Essa conquista mostra que Deus é fiel às suas promessas e que podemos confiar nele mesmo quando os desafios parecem grandes demais.', 'Josué 1:9'],
  ['FB02-L13', 'Jesus promiseu que voltaria para buscar seu povo e transformar este mundo em um lugar perfeito, onde não haverá mais sofrimento, lágrimas ou morte. Deus vai fazer um novo céu e uma nova terra, e todos que crêem e obedecem a Ele viverão eternamente com amor e paz. Essa esperança nos ajuda a ser fortes na fé e a valorizar as coisas de Deus acima das coisas deste mundo.', 'Apocalipse 21:1'],
  ['FB02-L12', 'A Igreja de Jesus Cristo nasceu no dia de Pentecostes, quando o Espírito Santo desceu e encharcou os primeiros discípulos. A partir daquele momento, eles ganharam coragem para pregar o Evangelho, e a Igreja começou a crescer de forma surpreendente, alcançando pessoas de muitas nações. Deus quer que a Igreja continue crescendo hoje, e Ele nos dá a mesma força do Espírito Santo para cumprirmos essa missão.', 'Atos 1:8'],
  ['FB02-L08', 'Depois que Josué morreu, o povo de Israel ficou sem líder e começou a desobedecer a Deus. Cada vez que eles pecavam, Deus permitia que inimigos os dominassem, mas quando eles se arrependiam, Deus levantava um juiz para livrá-los. Com o tempo, o povo pediu um rei para governá-los, e Deus permitiu que Saul fosse o primeiro rei de Israel. Essa história nos mostra que Deus é paciente e está sempre pronto para nos ajudar quando nos voltamos paraEle.', 'Juizes 2:18'],
  ['FB02-L11', 'Deus prometeu desde o Antigo Testamento que enviaria um Salvador ao mundo. Os profetas anunciaram que este Messiah nasceria, faria maravilhas e traria a salvacao para todos. Quando Jesus nasceu em Belem, a promessa de Deus se cumpriu de forma maravilhosa, mostrando que Ele cumpre sempre o que diz.', 'Isaías 9:6'],
  ['FB03-L02', 'O Novo Testamento tem 27 livros organizados em quatro grupos principais. Os quatro primeiros são os Evangelhos, que contam a história de Jesus. O livro de Atos fala sobre a Igreja beginning. Depois vem 21 epistolas, que são cartas ensinando sobre a fé. Por fim, o livro de Apocalipse mostra promessas para o futuro. Essa organização ajuda a gente a entender melhor cada parte da Palavra de Deus.', '2 Timoteo 3:16'],
  ['FB03-L05', 'Os livros poéticos e sapienciais são uma parte muito especial da Bíblia. Diferente dos livros históricos que contam fatos, esses livros usam poesia, imagens e reflexões profundas para nos ensinar sobre Deus e sobre como viver com sabedoria. Os principais são Jó, Salmos, Provérbios, Eclesiastes e Cânticos dos Cânticos. Eles nos ajudam a entender que buscar a sabedoria de Deus é algo precioso e essencial para a nossa vida.', 'Provérbios 2:6'],
  ['FB03-L01', 'O Antigo Testamento possui 39 livros organizados de forma bem organizada, como uma grande biblioteca sagrada. Os livros são divididos em três grupos principais: primeiro vem a Lei, que são os cinco primeiros livros escritos por Moisés; depois vêm os Livros Históricos, que contam a história do povo de Deus; e por fim os Livros Poéticos e Proféticos, que incluem os Salmos e as mensagens dos profetas. Essa organização nos ajuda a encontrar e entender melhor cada parte da Palavra de Deus.', 'Josue 1:8'],
  ['FB02-L06', 'Deus chamou Moisés para libertar o povo hebreu da escravidão no Egito. Por meio dos dez flagelos, da Páscoa e da travessia do Mar Vermelho, Deus demonstrou Seu poder sobre os deuses do Egito. No monte Sinai, Deus fez uma aliança especial com Israel, dando-lhe os Dez Mandamentos e as leis. Assim, de um grupo de escravos, Deus formou uma nação которая O adoraria e O representaria perante todos os povos.', 'Êxodo 19:5-6'],
  ['FB03-L07', 'Os profetas menores são doze livros da Bíblia que recebem esse nome não porque sejam menos importantes, mas porque são mais curtos que os livros dos profetas maiores, como Isaías e Jeremias. Eles viveram em diferentes épocas da história de Israel e Judá, e trouxeram mensagens de Deus sobre justiça, arrependimento e esperança. Cada um deles nos ajuda a entender como Deus age e se importa com o Seu povo em todos os tempos.', 'Miqueias 6:8'],
  ['FB02-L03', 'No inicio, Deus criou o ser humano e colocou Adao e Eva no Jardim do Éden, onde tudo era perfeito e eles podiam viver em plena comunhao com Deus. O problema surgiu quando a serpente, que era mais astuta que todos os animais do campo, conseguiram convencer Eva a duvidar das palavras de Deus e a comer do fruto que Ele havia prohibido. Ao desobedecerem a Deus, Adao e Eva trouxeram o pecado para toda a humanidade, e desde aquele dia todos os seres humanos nasceram com uma tendencia ao pecado, separada de Deus. Essa historia nos mostra que Deus nos ama muito, mas nos deu o livre-arbítrio, e quando escolhemos desobedecer-Lhe, trazemos consequências para a nossa vida e para o mundo ao nosso redor.', 'Genesis 3:1-6'],
  ['FB03-L06', 'Os profetas maiores sao quatro grandes livros da Biblia: Isaías, Jeremias, Ezequiel e Daniel. Esses homens de Deus foram escolhidos para entregar mensagens importantes diretamente do Senhor ao povo de Israel e tambem as nacoes ao redor. Cada um deles viveu em epocas diferentes da historia biblica, mas todos tinham uma missao especial: chamar o povo de volta para Deus, avisar sobre os castigos pelos pecados e tambem trazer esperanca de um futuro melhor quando o povo se arrependesse. Os profetas maiores nos ensinam que Deus sempre esta falando conosco e tem um plano perfeito para nossas vidas.', 'Isaías 46:9-10'],
  ['FB03-L10', 'As Cartas Paulinas sao cartas que o apostolo Paulo escreveu para igrejas e pessoas,，就好像 quando voce escreve uma carta para um amigo. Paulo escreveu muitas dessas cartas para ensinar, corrigir e encorajar os crentes. Hoje, essas cartas formam uma grande parte do Novo Testamento e nos ajudam a entender a fe cristã de forma pratica e profunda.', 'Romanos 1:16'],
  ['FB03-L09', 'O livro de Atos dos Apóstolos e a continuacao do Evangelho de Lucas. Ele conta a historia da Igreja que nasceu apos Jesus subir aoceu. Nesse livro, vemos como os primeiros cristaos viveram juntos, como o Espirito Santo desceu no dia de Pentecostes e como a Palavra de Deus se espalhou por muitas terras. E um livro cheio de coragem e f", porque mostra que, mesmo com dificuldades, Deus estava com o seu povo.', 'Atos 1:8'],
  ['FB03-L11', 'As cartas gerais são um conjunto de sete livros do Novo Testamento escritos por apóstolos e líderes da igreja primitiva. Diferente das cartas de Paulo, que foram enviadas a igrejas ou pessoas específicas, essas cartas foram escritas para um público mais amplo, abordando temas como a fé, a paciência, o amor e a proteção contra falsos ensinamentos. Elas nos mostram como viver uma vida cristã fiel no dia a dia, mesmo diante de dificuldades e tentações.', 'Tiago 1:22'],
  ['FB03-L13', 'A Biblia e um livro muito especial que foi organizado em capitulos e versiculos para nos ajudar a encontrar mais facilmente os textos que queremos ler e estudar. Cada livro tem capitulos, e cada capitulo tem versiculos, que sao como numeros deEndereco da Palavra de Deus. Assim, quando alguien diz \'Salmos 23:1\', ja sabemos que e o livro de Salmos, capitulo vinte e tres, versiculo um.', 'Salmo 119:105'],
  ['FB04-L01', 'Deus e o grande Criador de tudo o que existe. No inicio, ele criou os ceus e a terra do nada, apenas com a sua palavra. Toda a vida, a luz, os animais e nos, seres humanos, viemos das mos amorosas de Deus. Ele nos fez com um proposito especial e nos ama muito.', 'Genesis 1:1'],
  ['FB03-L14', 'Os judeus organizavam o Antigo Testamento de uma forma bem especial, dividindo tudo em três grandes grupos: primeiro, a Lei de Deus, que é o Pentateuco - os cinco primeiros livros que contam desde a criação até a entrada do povo na terra prometida; segundo, os livros dos Profetas, que contam a história de Israel e trazem mensagens de Deus spoken pelos profetas; e terceiro, os Escritos, que incluem livros como Salmos, Provérbios e Jó. Esse nome especial em hebraico para toda a Bíblia hebraica é Tanak, formado pelas iniciais dessas três partes.', 'Deuteronomio 31:9'],
  ['FB03-L15', 'Deus revelou-se ao ser humano ao longo de toda a historia. No Antigo Testamento, Ele falou pelos profetas e fez promessas ao povo de Israel. No Novo Testamento, essas promessas se cumpriram com a vinda de Jesus Cristo. Os dois testamentos formam uma unica historia da salvacao: o Antigo prepara e aponta para o Novo, e o Novo Cumprimento revela o sentido completo do Antigo. Por isso, ler a Biblia inteira nos ajuda a entender melhor o plano de Deus para nos.', 'Hebreus 1:1-2'],
  ['FB04-L02', 'Quando Deus criou o ser humano, Ele nos fez bons e sem pecado, placedo no lindo Jardim do Éden. Mas Adão e Eva decidiram desobedecer a Deus, comeram do fruto proibido e com isso trouxeram o pecado para toda a humanidade. Essa desobediência é chamada de Queda. Desde aquele dia, todos nós nascemos com uma natureza pecaminosa e precisamos do amor de Deus para sermos restaurados. Mas não se preocupe: Deus já tinha um plano de salvação preparado para nós!', 'Génesis 3:9'],
  ['FB03-L12', 'A literatura apocalíptica é um estilo de escrita usado na Bíblia para mostrar que Deus um dia vai transformar completamente o mundo, trazendo justiça e paz. Os textos apocalípticos usam muitas imagens e símbolos, como animais e números, para ensinar verdades profundas sobre o poder de Deus e a esperança que temos no futuro. Quando lemos esses textos, devemos lembrar que eles foram escritos para dar coragem aos seguidores de Deus que estavam passando por momentos difíceis, mostrando que Deus está no controle de tudo.', 'Apocalipse 1:1'],
  ['FB04-L03', 'Desde o inicio do mundo, quando o pecado entrou na vida das pessoas, Deus ja tinha um plano de amor para nos resgatar. Ele prometeu que enviaria um Salvador, alguém especial que venceria o mal e traria de volta a paz entre nós e Ele. Essa promessa é como um fio de esperança que atravessa toda a Biblia, ficando cada vez mais forte ate a vinda de Jesus.', 'Gênesis 3:15'],
  ['FB04-L07', 'Deus ouviu o clamor do seu povo que sofria na escravidão do Egito e chamou Moisés para liderar a saída dos israelitas. Através de grandes milagres, Deus mostrou seu poder sobre os deuses dos egípcios e libertou o seu povo com braço poderoso. Essa saída do Egito, chamada êxodo, é a maior demonstração de Deus resgatando o seu povo e se torna uma figura da salvação que Jesus nos oferece.', 'Êxodo 6:6'],
  ['FB03-L04', 'Os livros historicos da Biblia sao aqueles que contam a historia do povo de Deus desde a entrada na Terra Prometida ate os tempos da Igreja. Eles registram guerras, conquistas, reis, profetas e os caminhos que Deus fez junto ao seu povo ao longo dos seculos. Esses livros nos ajudam a entender como Deus age na historia e o que podemos aprender com as experiencias dos personagens biblicos.', '1 Corintios 10:11'],
  ['FB04-L05', 'Deus fez algo extraordinário: chamou um homem chamado Abrão para deixar sua família, sua terra e tudo o que conhecia, para ir a um lugar que Deus ia mostrar. Abraão não sabia para onde ia, mas obedeceu porque confiou em Deus. Esse ato de fé de Abraão foi tão importante que ele se tornou o pai de todos os que creem. Quando obedecemos a Deus mesmo sem entender tudo, estamos seguindo o exemplo de fé de Abraão.', 'Hebreus 11:8'],
  ['FB04-L04', 'Depois do dilúvio, Deus fez uma promessa muito especial para Noé e para todos nós: Ele nunca mais destruiria a terra por meio de águas. Deus colocou o arco-íris no céu como um sinal visível dessa promessa, lembrando-nos todos os dias que Ele cumpre Sua palavra e que nos ama. Essa aliança é diferente das outras porque Deus a fez com toda a criação, com todos os seres vivos, mostrando que Sua graça e cuidado alcançam cada canto do mundo que Ele fez.', 'Genesis 9:11'],
  ['FB04-L08', 'Quando o povo de Israel estava no deserto, Deus chamou Moisés ao monte Sinai e fez uma promessa muito especial: se o povo obedecesse aos mandamentos dele, seria o povo dele, querido e protegido por Deus. Esse acordo entre Deus e Israel se chama Aliança do Sinai, e mostra como Deus quer estar perto de nós e cuidar de nós quando respondemos ao seu amor com obediência e fé.', 'Exodo 19:5'],
  ['FB04-L06', 'Deus escolheu uma família para formar um povo especial: Israel. Tudo começou quando Deus chamou Abraão e fez uma promessa: ele teria muitos descendentes e seria uma grande nação. Com o tempo, essa família cresceu e se tornou um povo inteiro. Depois de séculos na escravidão do Egito, Deus os libertou e fez uma aliança especial com eles no monte Sinai, dando-lhes sua lei e seu nome. Israel foi formado não por acaso, mas pelo plano amoroso de Deus para ser uma luz ao mundo e preparar o caminho para a vinda de Jesus.', 'Gênesis 12:2'],
  ['FB04-L11', 'Deus fez uma promessa muito especial ao rei Davi. Ele disse que a família de Davi seria para sempre o reino de Deus na terra. Isso significa que Jesus, que veio muito tempo depois, é o cumprimento dessa promessa divina, porque Ele nasceu da família de Davi. Deus sempre cumpre Suas promessas!', '2 Samuel 7:16'],
  ['FB04-L13', 'A Encarnacao de Cristo e o momento maravilhoso em que o Filho de Deus, que sempre existiu ao lado do Pai, decidiu deixar o ceu e se tornar um ser humano como nos. Ele nasceu de uma virgem, grew up como qualquer crianca, sentiu fome, sede, cansaco e ate tristeza. Tudo isso porque Ele nos amou tanto que quis viver entre nos para nos salvar. Jesus e Deus, mas tambem e verdadeiramente humano. Esse e o grande misterio da nossa fe: Deus se fez gente para que nos pudessemos nos tornar filhos de Deus.', 'Joao 1:14'],
  ['FB04-L10', 'Quando o povo de Israel pediu a Deus para ter um rei, como as outras nações, Ele permitiu, mas mostrou que o rei deveria seguir os Seus mandamentos. Deus escolheu Saul primeiro, mas depois Ele escolheu Davi, um jovem pastor, para ser o grande rei de Israel. O reino de Israel nos ensina que Deus tem um plano perfeito para o Seu povo, e quando confiamos Nele, Ele nos guia pelos melhores caminhos, assim como um rei sábio guia o seu reino com justiça e amor.', '1 Samuel 16:7'],
  ['FB04-L12', 'Quando o povo de Israel desobedeceu a Deus, Ele permitiu que fosse levado cativo para a Babilônia. Porém, mesmo no sofrimento do exílio, Deus não abandonou o Seu povo. Ele enviou profetas para consolationá-los e anunciar que a restoration viria, mostrando que o amor de Deus é fiel mesmo quando nos disciplina.', 'Jeremias 29:11'],
  ['FB04-L09', 'Deus, na sua infinita bondade, sabia que o ser humano precisava de um meio para se aproximar dele e receber o perdão dos pecados. Por isso, desde os tempos antigos, ele estabeleceu um sistema muito bonito: os sacrifícios e o sacerdócio. Os sacrifícios eram ofertas que o povo apresentava, geralmente de animais perfeitos, que simbolizavam a entrega e a morte como pagamento pelo pecado. Já os sacerdotes eram homens escolhidos por Deus para representar o povo diante dele, oferecendo esses sacrifícios no lugar certo e no tempo certo. Tudo isso era uma prévia, uma sombra do que estava por vir: Jesus Cristo, o nosso Grande Sacerdote, que se ofereceu como sacrifício perfeito e definitivo para nos salvar para sempre.', 'Hebreus 9:22'],
  ['FB04-L15', 'Quando Jesus subiu ao céu, Ele prometeu que enviaria o Espírito Santo para estar com Seus seguidores. No dia de Pentecostes, cinquenta dias depois da Páscoa, o Espírito Santo desceu sobre os discípulos de uma maneira muito especial - como vento forte e chamas de fogo. Neste dia, Pedro pregou o primeiro sermon e tres mil pessoas creram e foram batizadas. Assim nasceu a Igreja de Jesus Cristo! Ela começou com pessoas comuns que amavam a Jesus e queriam falar dEle ao mundo.', 'Atos 2:47'],
  ['FB04-L16', 'Desde o principio, Deus teve um plano de alcance universal. Ele escolheu um povo para abençoar todas as nacoes da terra. Essa missionariedade esta no centro da Historia da Redencao, porque Deus quer que todos os povos cheguem ao conhecimento da verdade e participem da sua salvacao.', 'Atos 1:8'],
  ['FB04-L17', 'A consumacao da redencao significa que Jesus Cristo completou toda a obra necessaria para nos salvar. Quando ele morreu na cruz, ressuscitou e subiu ao ceu, a redenção do povo de Deus ficou totalmente pronta. Isso e maravilhoso porque nao depende de nada que facamos para completar a salvacao - Jesus ja fez tudo por nos. Agora, ele esta no ceu intercedendo por nos e um dia voltara para levar seu povo para perto de si.', 'Hebreus 10:14'],
  ['FB05-L05', 'Depois que o povo de Israel conquistou a terra de Canaã, eles não tinham um rei para governar. Então, Deus levantou homens e mulheres especiais chamados juizes, que eram lideres escolhidos por Deus para ajudar o povo. O problema é que o povo ficava desobediente a Deus, e por isso sofria com inimigos ao redor. Mas quando eles se arrependiam e pediam ajuda, Deus enviava um juiz para livrá-los. Esse tempo é chamado de Periodo dos Juizes e nos ensina que precisamos ser fieis a Deus todos os dias, porque sem Ele, acabamos nos afastando.', 'Juizes 21:25'],
  ['FB05-L01', 'A Bíblia começa mostrando como Deus criou todo o universo e tudo o que existe. Nos primeiros capítulos de Gênesis, aprendemos que Deus falou e as coisas passaram a existir, mostrando Seu poder e sabedoria. Esse estudo da cronologia das origens nos ajuda a entender a sequência dos eventos criados por Deus, desde a criação do céu e da terra até a formação do primeiro homem e da primeira mulher. Conhecer essa ordem nos permite valorizar ainda mais a obra criadora de Deus e o plano que Ele teve desde o princípio.', 'Gênesis 1:1'],
  ['FB05-L06', 'A monarquia unida foi o período em que Israel viveu sob um único rei, começando com Saul, passando por Davi e terminando com Salomão. Esse tempo representou aproximadamente 120 anos de história, desde cerca de 1050 a.C. até 931 a.C., quando o reino se dividiu em Israel e Judá. Cada rei trouxe mudanças importantes para a história do povo de Deus, e entender a ordem e o tempo desses reinados nos ajuda a compreender melhor como Deus conduziu a história do seu povo.', '1 Reis 2:11'],
  ['FB05-L07', 'Depois que o reino de Israel se dividiu, as tribos do norte formaram um reino separado que durou cerca de 210 anos. Durante esse tempo, muitos reis se succederam no trono do norte, e a maioria deles fez coisas que desagradavam a Deus. Mesmo assim, Deus enviou profetas como Elias e Eliseu para chamar o povo de volta para Ele. Essa cronologia nos ajuda a entender como Deus esteve presente mesmo em tempos difíceis.', '1 Reis 15:34'],
  ['FB05-L03', 'A cronologia do Êxodo nos mostra que Deus age com precisao em seu plano de salvacao. Durante 430 anos, o povo de Israel viveu no Egito, e quando chegou o tempo determinado por Deus, Ele os tirou de la com mao forte e braco estendido. Cada evento, desde as dez pragas ate a travessia do Mar Vermelho, aconteceu no momento exato que Deus havia planejado desde a promessa feita a Abraao. Isso nos ensina que Deus e fiel aos seus cronogramas, e podemos confiar que suas promessas se cumprirao no tempo certo.', 'Exodo 12:41'],
  ['FB05-L04', 'A conquista de Canaã foi o cumprimento da promessa que Deus fez a Abraão, muitos anos antes. Josué, successor de Moisés, liderou o povo de Israel na entrada e conquista da terra prometida. Esse período aconteceu logo após a saída do Egito e a travessia do deserto, seguindo um plano divino que mostra a fidelidade de Deus em cumprir Suas palavras. A chronologia dessa conquista nos ajuda a entender como Deus conduziu a história do Seu povo passo a passo.', 'Josue 1:6-9'],
  ['FB05-L09', 'Os profetas biblicos foram mensageiros de Deus em diferentes epocas da historia de Israel e do povo de Deus. Eles podem ser divididos em profetas pre-exilicos, que falaram antes do cativeiro na Babilonia, e profetas pos-exilicos, que falaram depois que o povo voltou para casa. Conhecer a ordem em que esses profetas viveram nos ajuda a entender melhor o contexto de cada mensagem que Deus lhes deu para compartilhar conosco.', 'Amos 3:7'],
  ['FB05-L11', 'A cronologia do retorno dos Judeus do cativeiro da Babilonia e um dos eventos mais importantes da historia biblica. Deus usou reis como Ciro, Dario e Artaxerxes para permitir que o povo voltasse para a terra de Israel em diferentes ondas, primeiro para reconstruir o templo e depois para reconstruir os muros de Jerusalem. Esse retorno aconteceu conforme as palavras do profeta Jeremias, que tinha dito que apos setenta anos de cativeiro, Deus traria o Seu povo de volta. Assim, podemos ver que Deus tem o controle da historia e cumpre todas as suas promessas no tempo certo.', 'Jeremias 29:10'],
  ['FB04-L14', 'A morte de Jesus na cruz nao foi apenas uma traggedia, mas o plano perfeito de Deus para nos resgatar do pecado e da morte. Quando Cristo disse \'Está consumado\', Ele pagou o preco completo por todos os nossos pecados, oferecendo-nos o perdão e a vida eterna. Mas a historia nao terminou ali! Tres dias depois, Deus ressuscitou Jesus dos mortos, mostrando que Ele tem poder sobre a morte e garantindo que todos que crem Nele tambem terao vida nova. A ressurreicao e a prova maxima de que Jesus e o Filho de Deus e que a nossa fe e baseada em algo verdadeiro e poderoso.', '1 Corintios 15:3-4'],
  ['FB05-L08', 'O Reino do Sul, também chamado de Reino de Judá, durou cerca de 390 anos, desde que o reino foi dividido após o rei Salomão até a destruição de Jerusalém pelos babilônios. Durante esse tempo, muitos reis governaram Judá, alguns foram bons e obedeceram a Deus, como Ezequias e Josias, enquanto outros foram maus e levaram o povo para a desobediência. Deus enviou profetas para chamar o povo ao arrependimento, mas quando não se arrependeram, o julgamento chegou. Mesmo nos momentos mais difíceis, Deus prometeu um dia restaurar o seu povo e enviar o Messias.', '2 Cronicas 36:15'],
  ['FB05-L13', 'Jesus nasceu em Belém, viveu sua infância em Nazaré e começou seu ministério público por volta dos trinta anos de idade. Durante aproximadamente três anos, ele ensinou, realizou milagres e pregou o Reino de Deus por diversas regiões. Depois de sua morte, ressurreição e ascensão, seus apóstolos continuaram pregando o evangelho pelo mundo.', 'Lucas 3:23'],
  ['FB06-L01', 'Quando lemos a Biblia, precisamos lembrar que ela aconteceu em um lugar muito real: o Antigo Oriente Próximo. Era uma regiao cheia de grandes rios, desertos, cidades poderosas e povos diferentes que se comunicavam entre si. Jesus, os patriarcas e os profetas viviam nesse mundo, cercados por essas civilizações, e entender isso ajuda a compreender melhor as histórias que Deus nos contou.', 'Jeremias 25:11'],
  ['FB05-L15', 'Paulo, tambem chamado Saulo antes de sua conversao, realizou tres grandes viagens missionarias que levaram o evangelho da Asia Menor ate a Europa. A primeira viagem missionaria aconteceu logo apos a Igreja comecar a se espalhar entre os nao-judios. Na segunda viagem, Paulo e Silas percorreram muitas cidades, enfrentando dificuldades mas tambem vendo muitas pessoas se converterem. A terceira viagem foi a mais longa, e durante ela Paulo escreveu cartas que hoje fazem parte do Novo Testamento. Entender quando cada viagem aconteceu nos ajuda a ver como a mensagem de Jesus foi se espalhando pelo mundo antigo.', 'Atos 13:1-3'],
  ['FB06-L03', 'O Egito foi um dos paises mais importantes na historia da Biblia. La, Jose foi escravo e depois se tornou governador, salvando sua familia da fome. La tambem, Deus chamou Moises para libertar o povo de Israel da escravidao. O rio Nilo, que atravessa o Egito, foi essencial para a vida daquele povo. O Egito aparece varias vezes na Biblia como um lugar de provacao e tambem de protecao para os personagens biblicos.', 'Exodo 3:10'],
  ['FB06-L04', 'Canaã é a terra que Deus prometeu a Abraão, nosso pai na fé. Era uma terra rica em leite e mel, onde o povo de Israel morou por muitos anos. Ela fica numa região muito especial, entre a África e a Ásia, por onde passavam muitas rotas de viagem. Quando lemos as histórias da Bíblia e encontramos lugares como Jerusalém, Belém ou Nazaré, estamos falando de cidades que ficam na terra de Canaã, a terra que Deus escolheu para o seu povo.', 'Êxodo 3:17'],
  ['FB05-L16', 'As cartas do Novo Testamento foram escritas em momentos diferentes da historia da igreja primitiva, principalmente pelo apostle Paulo e por outros lideres como Pedro, Joao, Tiago e Judas. Conhecer a ordem em que essas cartas foram escritas nos ajuda a entender o contexto em que cada uma foi enviada e como a mensagem de Deus foi se desenvolvendo ao longo do tempo.essa cronologia nos mostra que a Palavra de Deus foi registrada de forma gradual, conforme as necessidades do povo de Deus iam surgindo.', '2 Pedro 3:15-16'],
  ['FB06-L02', 'Mesopotamia e uma palavra grega que significa \'terra entre dois rios\'. Esses rios sao o Eufrates e o Tigre, que ficam na regiao onde hoje ficam paises como Irak e Syria. Essa regiao e muito importante na Biblia porque foi ali que Deus chamou Abraao para comecar a historia do povo de Israel. Muitos episodios da Biblia aconteceram nessa terra, desde a criacao do mundo ate os tempos dos patriarcas.', 'Genesis 15:7'],
  ['FB06-L06', 'Galileia era uma região no norte de Israel, onde Jesus cresceu e viveu a maior parte de sua vida. O nome Galileia vem de uma palavra que significa \'região dos povos\' porque ali viviam pessoas de várias nações. Mesmo sendo uma região simples e muitas vezes desprezada pelas pessoas da capital, foi exatamente ali que Deus escolheu para começar a obra de Jesus e revelar Seu amor a todos. A Galileia nos ensina que Deus Often usa lugares e pessoas humildes para fazer coisas maravilhosas.', 'Isaías 9:1-2'],
  ['FB06-L05', 'A Terra de Israel foi promessa de Deus ao povo hebreu. Ela fica na região do Oriente Médio, entre o mar Mediterrâneo e o deserto, e é um lugar muito especial porque lá aconteceram muitas histórias da Bíblia. Conhecer a geografia dessa terra nos ajuda a entender melhor os relatos bíblicos, pois o clima, os rios e as montanhas influenciaram a vida do povo de Deus.', 'Genesis 12:7'],
  ['FB06-L13', 'A Assíria ficava na região norte da Mesopotâmia, onde hoje está o Iraque. Era um império muito forte e cruel, conhecido por seus exércitos poderosos que destruíram o Reino do Norte de Israel. Deus permitiu que os assírios castigassem o povo de Israel quando ele se afastava de Deus. A cidade de Nínive era a capital desse grande império.', '2 Reis 17:6'],
  ['FB06-L11', 'Os desertos e as montanhas da Biblia sao muito mais do que simples lugares geograficos: sao palco onde Deus agiu de maneira poderosa na vida do Seu povo. O deserto foi escola de fe para os israelitas, onde aprenderam a confiar em Deus mesmo sem ter o necessario para sobreviver. Ja as montanhas foram lugares onde Deus Se revelou, como o Monte Sinai onde entregou os Dez Mandamentos e o Monte das Oliveiras onde Jesus orava. Assim, tanto os desertos quanto as montanhas nos ensinam que Deus esta presente em toda circunstancia e quernos encontrar tambem nos momentos mais dificeis da nossa vida.', 'Salmos 121:1'],
  ['FB06-L09', 'Jerusalém é uma das cidades mais importantes de toda a Bíblia. Ela foi a capital do Reino de Israel, o lugar onde ficava o Templo de Deus, e também a cidade onde Jesus morreu na cruz e ressuscitou. Por isso, ela é chamada de cidade santa. Quando oramos por Jerusalém, estamos seguindo o exemplo dos salmistas que pediam a paz para esse lugar especial.', 'Salmos 122:6'],
  ['FB06-L07', 'Samaria foi uma cidade muito importante na historia biblica. Era a capital do Reino Norte de Israel, construida pelo rei Omri. Depois que o reino foi destruido, a cidade continuou existindo e os samarios se tornaram um povo com suas proprias tradicoes. O mais emocionante e que, apos a ressurreicao de Jesus, o evangelho chegou ate la, mostrando que a salvacao e para todos os povos, sem distincao. Samaria fica exatamente no caminho entre Judea e Galilee, por isso era um lugar de muita passagem e influencia.', 'Joao 4:5-6'],
  ['FB06-L17', 'O Imperio Romano foi o grande poder politico que dominava a Terra de Israel quando Jesus nasceu, viveu e morreu. Os romanos criaram estradas, mantiveram a paz e tambem impuseram impostos e regras que o povo hebreu tinha que seguir. Quando a Biblia fala de Cesar, de Pilatos e de soldados romanos, ela esta se referindo a esse imperio poderoso que Deus permitiu que existisse para que a historia da salvacao pudesse acontecer. Compreender isso nos ajuda a entender melhor os desafios que Jesus e os primeiros cristas enfrentaram.', 'Lucas 2:1'],
  ['FB06-L14', 'O Império Babilônico foi um dos maiores impérios da antiguidade, com capital na cidade de Babilônia, que ficava onde hoje é o Iraque. Deus permitiu que esse império se erguesse para cumprir Seus planos, inclusive usando o rei Nabucodonosor como instrumento para disciplinar o povo de Israel. A cidade de Babilônia era muito poderosa e symbolizada por uma taça que fazia as nações enlouquecerem, mas Deus mostrou que nenhum império humano é permanente diante dEle.', 'Jeremias 51:7'],
  ['FB06-L18', 'Paulo fez três grandes viagens missionárias, percorrendo diversas regiões do Mediterrâneo para levar a notícia salvadora de Jesus a pessoas que nunca tinham ouvido sobre o Salvador. Nessas jornadas, ele enfrentou perigos, tempestades, prisões e até picada de cobra, mas nunca deixou de pregar o evangelho. Essas viagens nos ensinam que Deus nos chama para sermos seus instrumentos na divulgação do Reino, onde quer que estejamos.', 'Romanos 15:20'],
  ['FB06-L10', 'O Rio Jordao e um dos rios mais importantes da Biblia, pois foi nele que Jesus Cristo foi batizado por Joao Batista. O Mar Morto e um lago muito especial que fica na mesma regiao, sendo chamado assim porque nenhuma vida consegue sobreviver em suas aguas salgadas. Esses dois lugares foram palco de muitos milagres e momentos importantes na historia da fe, e hoje podemos visita-los e conhecer de perto onde a Biblia aconteceu!', 'Marcos 1:9'],
  ['FB06-L16', 'O Império Grego foi fundado por Alexandre Magno, que conquistou diversas terras ao redor do Mediterrâneo por volta do século IV antes de Cristo. Depois que Alexandre morreu, seu império foi dividido entre seus generais, que criaram reinos como o Egito, a Siria e a Grécia. Esse período helenístico é muito importante para entendermos o contexto dos livros históricos e dos profetas do Antigo Testamento, além do cenário político e cultural em que muitos livros do Novo Testamento foram escritos.', 'Daniel 8:21-22'],
  ['FB07-L02', 'Deus criou o casamento para ser uma união sagrada entre um homem e uma mulher, baseada no amor e no compromisso. O noivado é o tempo de preparação e compromiso antes da vida juntos, onde os noivos aprendem a se conhecer melhor e a construir uma relação com bases firmes na fé. Na Bíblia, vemos que Deus abençoa o casamento e quer que ele seja tratado com respeito e seriedade, seguindo os Seus ensinamentos.', 'Génesis 2:24'],
  ['FB06-L19', 'Jesus Cristo, por meio do apóstolo João, enviou mensagens a sete igrejas que ficavam na região da Ásia Menor, cada uma com uma situação espiritual diferente. Algumas estavam sendo fieis e outras haviam se afastado da vontade de Deus. Essas cartas nos ensinam que Deus conhece nossa vida e nos chama ao arrependimento e à fidelidade, seja qual for nossa situação espiritual hoje.', 'Apocalipse 2:5'],
  ['FB07-L03', 'Na Bíblia, o nascimento e a infância são momentos muito importantes, especialmente o nascimento de Jesus, que aconteceu em Belém. Assim como os pais de antigamente cuidavam de seus filhos com muito amor, Deus também cuida de cada um de nós desde que nascemos. A Bíblia nos mostra que Deus tem um plano especial para cada pessoa, desde a infância até a vida adulta.', 'Lucas 2:6-7'],
  ['FB07-L01', 'Deus criou a família desde o princípio do mundo, no jardim do Éden. Ele instituiu o casamento entre um homem e uma mulher para formarem um lar unido pelo amor. A família é o lugar onde aprendemos a amar, a cuidar uns dos outros e a conhecer a Deus. Por isso, a família é muito importante para Deus e Ele quer abençoar cada família que O aceita como centro do lar.', 'Marcos 10:9'],
  ['FB07-L04', 'Deus deseja que os pais ensinem seus filhos a conhecê-lo e a viver de forma justa. A Bíblia nos mostra que a família é o lugar principal onde aprendemos sobre Deus. Quando cuidamos da educação espiritual das crianças, estamos cumprindo a vontade de Deus e preparando pessoas para abençoar o mundo. Esse é um trabalho muito importante que traz alegrias e também desafios, mas Deus nos dá forças para isso.', 'Provérbios 22:6'],
  ['FB07-L05', 'A Bíblia nos ensina que o trabalho é uma bênção de Deus e uma forma de demonstrar amor ao próximo. Quando trabalhamos com dedicação e honestidade, estamoseding a Deus, pois Ele nos deu habilidades e oportunidades para servir. O verdadeiro propósito do trabalho não é apenas ganhar dinheiro, mas usar nossos talentos para ajudar os outros e glorify a Deus em tudo o que fazemos.', 'Colossenses 3:23'],
  ['FB07-L06', 'A agricultura e a criação de animais eram a base da vida no tempo da Bíblia. Deus entregou ao ser humano a tarefa de cuidar da terra e dos animais, desde o Jardim do Éden. Pastores, lavradores e criadores de gado aparecem em muitas histórias bíblicas, mostrando que o trabalho no campo é abençoado por Deus.', 'Gênesis 2:15'],
  ['FB07-L09', 'Na Bíblia, as casas e as cidades eram muito mais do que simples construções. Elas representavam a vida em comunidade, o cuidado de Deus e o lugar onde o povo se reunia para adorá-lo. Desde a casa de Abraão, que tinha um altar, até as cidades que Deus mandou os israelitas construirem, tudo isso mostra que o Senhor Se importa com os lugares onde vivemos.', 'Josué 24:13'],
  ['FB07-L10', 'Hospitalidade é a atitude de receber bem as pessoas, especialmente aquelas que não conhecemos, com amor e cuidado. Deus nos ensina que acolher o próximo é um ato de amor que abençoa tanto quem recebe quanto quem oferece. Quando мы abrimos nosso coração e nossa casa para os outros, estamos vivendo a vontade de Deus e refletindo o amor de Cristo.', 'Hebreus 13:2'],
  ['FB07-L11', 'No tempo de Jesus, existiam diferentes tipos de moedas que circulavam na região. O denário era a moeda mais usada no dia a dia, equivalente ao salário de um trabalhador por um dia de trabalho. Também existiam outras moedas, como o siclo, usado para pagar impostos do Templo. Quando Jesus e seus discípulos precisavam comprar comida ou pagar tributos, eles usavam essas moedas. Jesus ensinou que o dinheiro é útil para as necessidades da vida, mas que o mais importante são as coisas do coração, não as riquezas materiais.', 'Mateus 22:21'],
  ['FB07-L12', 'No mundo antigo, a escravidão era algo muito comum e fazia parte da estrutura social. Muitas pessoas, por causa de guerras, dívidas ou nascimentos, viviam nessa condição difícil. A Bíblia não aprova a escravidão como algo ideal de Deus, mas mostra como ela existia na época, e apresenta princípios importantes sobre o valor de cada pessoa diante de Deus, mostrando que todos são igualmente importantes para Ele.', 'Colossenses 3:22-4:1'],
  ['FB07-L14', 'A Biblia nos ensina que o corpo fisico e importante para Deus. Quando uma pessoa morre, ela e sepultada com respeito e dignidade, seguindo o exemplo de Jesus, que tambem foi sepultado. Esse momento de dor tambem e preenchido com a esperan?a da ressurrei?ao, porque cremos que Cristo venceu a morte e que um dia todos os que creem nEle voltarao a viver.', '1 Tessalonicenses 4:14'],
  ['FB07-L16', 'Deus é santo e quer que o Seu povo se aproxime Dele com reverencia e cuidado. No tempo do Antigo Testamento, Deus deu regras sobre o que era impuro e como o povo deveria se purificar para poder adorar-Lo no Templo. Esses rituais ensinavam que se aproximar de Deus exige preparacao e respeito. Hoje, pela morte de Jesus na cruz, temos acesso direto a Deus, e a pureza que Ele quer vai alem do corpo: envolve nosso coracao e nossas acoes.', 'Levitico 19:2'],
  ['FB07-L15', 'As festas judaicas sao celebracoes que Deus mandou o povo de Israel guardar para lembrar as grandes coisas que Ele fez na historia. Cada festa tem um significado especial e, muitas delas, apontam para Jesus Cristo. Mesmo que hoje nao as celebremos exatamente como antigamente, elas nos ajudam a entender melhor o plano de Deus para nos.', 'Colossenses 2:16-17'],
  ['FB07-L19', 'Os costumes greco-romanos eram o contexto cultural no qual a Bíblia foi escrita, especialmente o Novo Testamento. Entender esses costumes nos ajuda a compreender melhor as situações vividas por Jesus, os apóstolos e as primeiras comunidades cristãs. Coisas como a forma de cumprimentar, os banhos públicos, as refeições e a organização das cidades faziam parte do dia a dia das pessoas daquela época. Quando conhecemos esses costumes, as histórias e ensinamentos bíblicos ficam muito mais vivos e claros para nós.', 'Atos 17:28'],
  ['FB07-L17', 'A sinagoga era um lugar muito importante para o povo judeu. Era onde eles se reuniam para orar, estudar a Palavra de Deus e aprender sobre a Lei. As sinagogas surgiram principalmente quando o povo estava longe de Jerusalém e não podia ir ao Templo. Lá, um líder chamado rabi ensinava as pessoas e rezavam juntos. Jesus frequentava as sinagogas e muitas vezes ensinava nelas, porque era um lugar de encontro com Deus e com a comunidade.', 'Lucas 4:16'],
  ['FB08-L01', 'Arqueologia bíblica é a ciência que estuda ruínas, objetos e vestígios de cidades antigas para confirmar e entender melhor os relatos da Bíblia. Ela não prova que a Bíblia é verdadeira — isso a fé nos ensina —, mas nos ajuda a ver que os lugares, os costumes e as pessoas mencionados nas Escrituras realmente existiram. É como se a terra guardasse testemunhas silenciosas que confirmam a história sagrada que já lemos na Palavra de Deus.', 'Jó 13:1'],
  ['FB07-L18', 'O templo era a casa de Deus, o lugar sagrado onde o povo de Israel ia para adorar, orar e se encontrar com o Senhor. No templo, os sacerdotes ofereciam sacrifícios e o povo participava das festas e celebrações. Mas Jesus nos ensinou que o verdadeiro culto nao depende apenas de um lugar especial, mas do nosso coracao. Deus quer que o adoremos em espirito e verdade, com sinceridade e amor, em qualquer lugar onde estejamos.', 'Joao 4:23-24'],
  ['FB08-L02', 'A arqueologia é uma ferramenta muito importante que nos ajuda a conhecer melhor o mundo bíblico, encontrando objetos, cidades e documentos antigos. Porém, ela tem limites: nem tudo da Bíblia pode ser comprovado ou encontrado por escavações, e muitos lugares ainda não foram descobertos. Isso não significa que a Bíblia seja menos verdadeira, mas sim que Deus nos dá fé para crer nas coisas que os olhos não podem ver. O mais importante é entender que a arqueologia pode confirmar a Bíblia, mas não é ela que torna a Palavra de Deus verdadeira.', '1 Coríntios 3:19'],
  ['FB08-L07', 'Na arqueologia biblica, uma estela e uma pedra grande ou monolitho onde eram escritas palavras importantes, como leis, tratados ou registros de eventos. Da mesma forma que hoje guardamos documentos importantes em arquivos, os povos antigos gravavam suas historIAS em pedras para que ficassem preservadas por muitos anos. Quando os arqueologos encontram essas estelas, eles podem comparar o que esta escrito ali com o que a Biblia conta, e isso nos ajuda a entender melhor os tempos biblicos e a confirmar a veracidade dos relatos sagrados.', 'Josue 24:27'],
  ['FB08-L09', 'Quando o rei Ezequias percebeu que o exército assírio estava se aproximando de Jerusalém, ele teve uma ideia brilhante: desviar as águas da fonte que ficava fora da cidade para dentro dos muros, para que o povo não ficasse sem água durante um possível cerco. Assim, os trabalhadores escavaram um túnel de mais de 500 metros através da rocha sólida, uma obra impressionante de engenharia antiga! Esse túnel existe até hoje e confirma a precisão histórica dos relatos bíblicos.', '2 Reis 20:20'],
  ['FB08-L08', 'A Inscricao de Tel Dan e um pedaco de pedra achado em escavacoes arqueologicas que tem escrita nele as palavras \'Casa de Davi\'. Isso e muito importante porque e a primeira prova FORA da Biblia de que o rei Davi existiu de verdade! E como se um amigo nosso confirmasse por escrito que a historia que contamos e verdadeira. Esse pedaco de pedra mostra que a arqueologia pode confirmar o que a Biblia nos conta.', '2 Samuel 7:16'],
  ['FB08-L05', 'As inscricoes antigas sao textos gravados em pedra, metal ou argila que nos ajudam a entender melhor a Biblia. Esses achados arqueologicos confirmam nomes de reis, cidades e ate mesmo detalhes de costumes que a Biblia menciona. Quando encontramos uma inscricao fora da Biblia que fala sobre o mesmo evento, isso fortalece nossa confianca de que a Palavra de Deus e confiavel. A arqueologia biblica e como um detective que usa pistas do passado para confirmar a verdade da Biblia.', 'Exodo 32:16'],
  ['FB08-L03', 'Quando os arqueologos querem descobrir vestigios de antigas civilicoes mentioned nas Escrituras, eles precisam usar metodos bem cuidadosos de escavacao. Cada camada de terra que e retirada revela pedacos da historia, como uma linha do tempo enterrada por Deus no solo. Os pesquisadores comecam tirando foto, marcando cada objeto encontrado e fazendo desenhos detalhados antes de mexer na terra. Assim, piece por piece, vamos entendendo melhor os tempos biblicos e confirmando a fidelidade das promessas de Deus registradas na Palavra.', 'Lucas 6:48'],
  ['FB08-L11', 'O Cilindro de Ciro e um pequeno documento em argila, escrito em escrita cuneiforme, que foi descoberto em 1879 nas escavacoes da antiga Babilonia. Esse documento mostra que Ciro, rei da Persia, permitiu que os povos captivos voltassem para suas terras nativas. Isso e muito importante para nos porque mostra que Deus cumpriu a promessa dele: que um rei pagão ordenaria a volta do povo de Israel para reconstruir o Templo em Jerusalem. Deus sempre cumpre as suas promessas, mesmo usando pessoas que talvez nem creiam nele.', 'Esdras 1:1-2'],
  ['FB08-L06', 'A Estela de Merneptá é uma pedra com inscrições egípcias que menciona Israel como um povo que existiu lá na terra de Canaã. Isso é muito especial porque mostra que Israel era conhecido por outras nações antigas, confirmando que a história da Bíblia é real. Essa inscrição tem mais de três mil anos e é a menção mais antiga de Israel fora da Bíblia.', 'Êxodo 1:9'],
  ['FB08-L10', 'O Prisma de Senaqueribe é um artefato de argila muito antigo que foi encontrado no Iraque e conta a história do rei Assírio Senaqueribe e sua invasão ao reino de Judá, durante o tempo do rei Ezequias. O prisma confirma que os eventos descritos na Bíblia são reais e aconteceram exatamente como a Palavra de Deus registra. Esse documento antigo mostra que Deus cumpriu Sua promessa de proteger Seu povo e que o orgulho do rei assírio foi derrotado.', '2 Reis 19:35'],
  ['FB08-L15', 'A arqueologia é uma ciência que estuda objetos e restos de civilizações antigas. Muitos arqueólogos já encontraram cidades, inscrições e artefatos que confirmam pessoas, lugares e eventos mencionados na Bíblia. Essas descobertas mostram que a Bíblia não é um livro de histórias inventadas, mas um documento que registra eventos reais da história. Quando a arqueologia confirma o que a Bíblia diz, isso nos dá mais confiança de que podemos confiar em tudo o que ela ensina.', 'Isaías 48:3'],
  ['FB09-L01', 'A palavra \'cânon\' vem de uma palavra grega que significava \'régua\' ou \'medida reta\'. Quando falamos do cânon bíblico, estamos falando dos livros que Deus inspirou e que a Igreja reconheceu como a regra certa e segura para告诉我们 a nossa fé. Assim como uma régua nos ajuda a medir, o cânon nos ajuda a saber quais são as verdadeiras palavras de Deus para nós. Esses livros foram escritos por pessoas escolhidas pelo Espírito Santo e foram confirmados pela comunidade de fiéis ao longo da história.', '2 Timóteo 3:16'],
  ['FB08-L16', 'Na arqueologia biblica, como em qualquer area do conhecimento, existem pessoas que cometem erros ou ate mesmo exageram na interpretacao das descobertas. Algumas vezes, objetos sao apresentados como provas biblicas quando na verdade nao tem nenhuma ligacao real com a Biblia. Por isso, e muito importante termos cuidado e nao aceitar tudo que lemos ou ouvimos sem verificar a fonte confiavel. Deus nos deu a capacidade de pensar e analisar, e Ele quer que usemos essa capacidade para buscar a verdade com humildade e honestidade.', '1 Tessalonicenses 5:21'],
  ['FB09-L02', 'O cânon do Antigo Testamento é a lista dos livros que Deus inspirou e que foram reconhecidos pelo povo de Israel como a sua Palavra Sagrada. Esse reconhecimento aconteceu aos poucos: primeiro os cinco livros da Lei, depois os livros dos profetas e finalmente os demais escritos sagrados. O povo hebreu guardava esses textos com muito carinho e fidelity, pois sabia que neles estava a vontade de Deus para a sua vida. Assim, aos poucos, Deus foi formando o Antigo Testamento que temos hoje, com 39 livros no total.', '2 Timóteo 3:16'],
  ['FB09-L03', 'A Bíblia Hebraica, também chamada de Tanak pelos judeus, é o Antigo Testamento organizado de forma diferente da que conhecemos. Ela é dividida em três partes: a Torá (os cinco livros da Lei), os Profetas e os Escritos. Os judeus reconheceram esses livros como inspirados por Deus ao longo de séculos, e esse reconhecimento foi sendo confirmado pela comunidade de fé. O termo \'Tanak\' vem das iniciais dessas três partes em hebraico.', 'Salmo 119:105'],
  ['FB08-L12', 'Os Manuscritos do Mar Morto sao copias de livros da Biblia e outros textos antigos, escritos em rolos de pergaminho, que foram encontrados em cavernas perto do mar Morto, em Israel. Eles tem mais de dois mil anos e sao muito importantes porque nos mostram que a Biblia foi bem guardada ao longo da historia. Quando comparamos esses manuscritos antigos com as nossas Biblias de hoje, vemos que a Palavra de Deus foi transmitida com muita fidelidade ao longo dos seculos.', 'Isaías 40:8'],
  ['FB09-L07', 'O cânon protestante é o conjunto dos 66 livros que formam a Bíblia aceita pelas igrejas evangélicas. Para um livro ser considerado canônico, ele precisa ter sido escrito por profetas ou apóstolos, estar de acordo com o ensino dos outros livros da Bíblia e ter sido aceito pela comunidade de fé desde cedo. Os protestantes rejeitam os livros apócrifos porque eles não atendem a esses critérios de canonicidade.', '2 Timóteo 3:16'],
  ['FB09-L04', 'A Biblia hebraica, que os judeus usam ate hoje, e organizada em tres grandes grupos: a Lei, que conta a historia da criacao do mundo e do povo de Israel desde Genesis ate Deuteronomio; os Profetas, que registram as mensagens que Deus enviou ao seu povo atraves de homens como Isaías, Jeremias e outros; e os Escritos, que incluem livros de sabedoria, poeticos e orações como os Salmos. Essa organizacao em tres partes e chamada pelos estudiosos de TaNaK, palavra formada pelas iniciais em hebraico dessas tres secoes.', 'Lucas 24:44'],
  ['FB09-L06', 'Os livros deuterocanônicos sao aqueles que facem parte da Biblia catolica, mas que nao estavam incluidos na colecao hebraica das Escrituras. O termo \'deuterocanonico\' significa literalmente \'segundo c anon\', pois esses livros foram reconhecidos oficialmente pela Igreja mais tarde, por volta do quarto seculo. Exemplos conhecidos sao Tobias, Judite, Sabedoria e os livros de Macabeus. A Igreja catolica considera esses textos inspirados por Deus, enquanto as igrejas reformadas e muitas comunidades evangelicas os veem apenas como leitura edificante, sem autoridade doctrinal.', '2 Macabeus 12:46'],
  ['FB09-L11', 'Quando as primeiras comunidades cristas quiseram saber quais livros eram verdadeiramente inspirados por Deus, elas usaram alguns critérios práticos. Olhavam se o livro tinha sido escrito por um apóstolo ou alguém bem perto deles, se o que ensinava combinava com o que Deus já havia revelado antes, se era aceito por muitas igrejas diferentes e se ajudava o povo a crecer na fé. Com o tempo, Deus guiou a Igreja a reconhecer quais livros formam a Bíblia que temos hoje.', 'Colossenses 2:2'],
  ['FB09-L12', 'Os livros apostólicos são as cartas e relatos do Novo Testamento escritos pelos apóstolos ou por pessoas bem próximas deles, como Lucas e Marcos. Como os apóstolos foram testemunhas diretas da vida, morte e ressurreição de Jesus, os seus escritos têm uma autoridade especial na fé cristã. Essas cartas não eram apenas cartas comuns, mas mensajes inspirados por Deus para guiar a Igreja. Por isso, a Igreja primitiva reconheceu esses livros como parte das Escrituras Sagradas.', 'Atos 1:21-22'],
  ['FB09-L09', 'A Igreja Ortodoxa, diferente de outros grupos cristãos, reconhece um conjunto de livros sagrados um pouco mais amplo que o protestante. Além dos livros que conhecemos, ela também aceita outros livros como parte da Bíblia, que chamamos de deuterocanônicos. Cada tradição cristã, ao longo da história, fez sua própria lista de livros inspirados por Deus, e é importante entender que isso não muda a verdade central da fé cristã.', '2 Timóteo 3:16'],
  ['FB09-L15', 'Os concílios eram encontros de líderes da igreja, como bispos e teólogos, que se reuniam para discutir questões importantes da fé. Um desses assuntos era decidir quais livros deveriam fazer parte da Bíblia, ou seja, quais eram os livros verdadeiramente inspirados por Deus. Eles analisavam se os livros tinham sido escritos por profetas ou apóstolos, se eram aceitos pelas igrejas e se ensinavam a verdadeira mensagem de Deus. Esse processo de seleção e aprovação recebeu o nome de cânon bíblico, que significa uma lista ou regra de livros sagrados.', '2 Timoteo 3:16-17'],
  ['FB10-L01', 'A revelação geral é a maneira como Deus se mostra a todas as pessoas através da natureza, da criação e da consciência. Quando olhamos para o céu, as estrelas, as árvores e tudo o que existe, podemos perceber que existe um Deus inteligente e poderoso que fez tudo com propósito e amor. Essa revelação está ao alcance de todos, em qualquer lugar e época, e nos permite conhecer algo sobre Deus mesmo antes de abrir a Bíblia.', 'Romanos 1:19-20'],
  ['FB09-L13', 'Na época da Igreja antiga, os primeiros cristãos recebiam muitas cartas e histórias escritas sobre Jesus e os apóstolos. Com o passar dos anos, as igrejas começaram a se perguntar: quais desses escritos são realmente de Deus e devem guiar nossa fé? Por isso, líderes e comunidades se reuniram para discutir, orar e decidir juntos quais livros contavam a verdadeira mensagem de Deus. Esse processo foi feito com muita seriedade e cuidado, para que os fiéis pudessem ter certeza do que estavam lendo na Bíblia.', '2 Timóteo 3:16'],
  ['FB09-L08', 'A palavra \'cânon\' vem do grego e significa \'regra\' ou \'medida\'. O cânon católico é a lista dos livros que a Igreja Católica reconhece como inspirado por Deus. Essa lista foi definida ao longo de varios seculos, culminando no Concilio de Trento em 1546. Os livros que fazem parte do cânon católico, mas nao estao na Biblia hebraica, sao chamados de deuterocanônicos. O cânon da Igreja Católica inclui 73 livros, differenciando-se de outras tradicoes como a protestante, que possui 66 livros.', '2 Timóteo 3:16'],
  ['FB10-L02', 'Revelação especial é a maneira como Deus se revelou de forma clara e direta ao ser humano, usando caminhos específicos. Ela inclui coisas como os profetas, os sonhos, as visões e, acima de tudo, a própria pessoa de Jesus Cristo. Deus quis que nós pudéssemos conhecê-lo melhor, e por isso escolheu falar de forma mais completa e direta com as pessoas, mostrando seu plano de amor para nós.', 'Hebreus 1:1-2'],
  ['FB10-L03', 'A Inspiração das Escrituras é a doutrina que nos ensina como Deus falou através de autores humanos. Deus Soprou o Seu Espírito nos escritores sagrados, guiando cada palavra que eles escreveram, sem tirar a personalidade deles. Assim, as Escrituras são ao mesmo tempo palavras humanas e palavra de Deus. Por isso podemos confiar que a Bíblia é a nossa regra segura de fé e prática.', '2 Timóteo 3:16'],
  ['FB09-L16', 'Quando falamos de como a Bíblia foi formada, existem alguns mitos, ou seja, ideias erradas que muitas pessoas acreditam. Um deles é achar que um grupo de bispos se reuniu e votou quais livros entrariam na Bíblia. Mas a verdade é que Deus guiou a Igreja ao longo de muitos anos para reconhecer os livros que Ele havia inspirado. Os livros não foram escolhidos por decisão humana, mas porque a igreja já sentia no seu coração que aquelas palavras vinham de Deus.', '2 Timóteo 3:16'],
  ['FB10-L05', 'A inspiração plenária é a doutrina que nos ensina que Deus conduziu os escritores sagrados de tal maneira que tudo o que eles escreveram foi exatamente o que Deus queria dizer, sem nenhum erro, em cada parte da Bíblia. Isso significa que a Bíblia é a Palavra de Deus, não apenas contendo a Palavra de Deus. Essa inspiração reachou todas as partes:história, poeira, ensinos e tudo mais, porque Deus quer que nossa fé seja fundamentada em Sua Palavra completa.', '2 Timóteo 3:16'],
  ['FB09-L14', 'Os evangelhos apocrifos sao escritos antigos que falam sobre a vida de Jesus, mas que nao foram aceitos pela Igreja primitiva como livros inspirados por Deus. Eles foram escritos por pessoas que nao eram apostolos, muitos anos depois dos fatos acontecerem. Por isso, a Igreja, guiada pelo Espirito Santo, escolheu apenas os quatro evangelhos que conhecemos - Mateus, Marcos, Lucas e Joao - porque eles foram escritos por quem conviveu com Jesus e receberam a sua mensagem diretamente. Esses evangelhos nao incluidos nos ajudam a entender a historia, mas nao tem a mesma autoridade da Biblia.', 'Atos 17:11'],
  ['FB10-L10', 'Deus, em sua sabedoria, nos deu as Escrituras Sagradas como um presente perfeito. A Bíblia é suficiente porque contém tudo o que precisamos para conhecer a Deus, entender a sua vontade e viver uma vida que agrada a ele. Não precisamos de outras fontes para completar o que as Escrituras já nos ensinam sobre a fé e o modo de viver.', '2 Timóteo 3:16-17'],
  ['FB10-L04', 'A inspiração verbal é a certeza de que Deus agiu sobre os escritores da Bíblia de maneira especial, para que cada palavra que eles escreveram fosse exatamente a palavra que Deus queria nos dizer. Isso não significa que Deus transformou os autores em robôs, mas sim que eleGUardou suas vontades e estilos pessoais enquanto os guiava com segurança. Assim, a Bíblia é completamente confiavell e não contém nenhum erro nas suas ensinanças. Podemos confiar nela como a voz de Deus falando diretamente a nós.', '2 Timóteo 3:16'],
  ['FB10-L09', 'A infalibilidade é uma qualidade wonderful que Deus deu à Sua Palavra. Isso significa que a Bíblia, como palavra de Deus inspirada pelo Espírito Santo, é completamente verdadeira e confiável em tudo o que ensina. Quando Deus falou, Ele não podia errar nem enganar, porque Ele é a própria verdade. Por isso podemos confiar que tudo o que a Bíblia diz é firme, seguro e não falha em nenhuma parte, desde as questões de fé até os fatos históricos e científicos que ela menciona.', 'Joao 17:17'],
  ['FB10-L12', 'Deus, em sua bondade, quis que tivéssemos um modo seguro de conhecer a sua vontade e o seu amor por nós. As Escrituras Sagradas são a sua voz registrada, que nos ensina, corrige e conforta em todos os momentos da vida. Sem a Palavra de Deus, ficariamos perdidos, sem direção certa para o nosso caminho.', '2 Timoteo 3:16'],
  ['FB10-L07', 'A autoridade bíblica significa que a Bíblia não é apenas um livro escrito por homens, mas é a Palavra de Deus com poder e validade para guiar a nossa vida. Quando a Escritura fala, é como se o próprio Deus estivesse falando conosco, porque ela vem dele. Por isso, podemos confiar nela como a verdade suprema e absoluta, acima de qualquer opinião humana.', 'João 17:17'],
  ['FB10-L06', 'Deus, ao inspirar a Bíblia, não transformou os escritores em robôs sem vontade própria. Ele escolheu pessoas reais, com suas histórias, culturas e estilos de escrita, e usou tudo isso para transmitir a mensagem perfeita dele. É como um maestro que rege músicos diferentes, cada um tocando seu instrumento, mas todos juntos formando uma sinfonia harmonia. Essa cooperação entre Deus e os humanos é o que torna a Bíblia tão rica e especial.', '2 Pedro 1:21'],
  ['FB10-L08', 'A inerrância bíblica nos ensina que a Bíblia, em seus originais escritos sob a inspiração do Espírito Santo, não contém erros ou contradições. Isso acontece porque Deus é perfeito e source de toda verdade, e Ele guiou os autores humanos de tal forma que suas palavras registraram exatamente o que Deus queria comunicar. Assim, podemos confiar plenamente que as Escrituras são confiáveis em tudo o que ensinam, desde questões de fé até detalhes históricos e científicos, porque são a palavra de Deus.', '2 Timóteo 3:16'],
  ['FB11-L03', 'Antes de existirem livros como os de hoje, Deus guardou suas palavras em pergaminhos. Esses eram feitos de pele de animais, bem resistentes, e os escribas escreviam à mão cada letra com muito cuidado e devotion. Deus foi muito fiel em preservar Sua Palavra através dos séculos, e os pergaminhos foram as primeiras páginas da Bíblia que conhecemos hoje.', 'Jeremias 36:2'],
  ['FB10-L11', 'Deus quer que nós entendamos a Sua Palavra! Por isso Ele a escreveu de forma clara, para que qualquer pessoa, mesmo sem ter estudado muito, possa compreender as verdades importantes da salvação e do amor de Deus. O Espírito Santo ajuda nosso coração a entender a Bíblia quando a lemos com sinceridade e fé. A Bíblia não é um livro misterioso só para especialistas, mas um presente de Deus para todos nós.', 'Salmo 119:130'],
  ['FB11-L05', 'Os manuscritos hebraicos sao os textos originais em hebraico que contem os livros do Antigo Testamento. Durante milhares de anos, escribas judeus copiaron esses textos com muita devocao e cuidado, preservando a mensagem de Deus com fidelity. Graças a esse trabalho fiel, podemos confiar que a Palavra de Deus chegou ate nos.', 'Isaias 40:8'],
  ['FB11-L02', 'Os papiros são alguns dos manuscritos bíblicos mais antigos que possuímos. Eles eram escritos em um material feito a partir de uma planta que crescia às margens do Rio Nilo, no Egito. Muitos desses documentos contêm trechos do Novo Testamento e nos ajudam a conhecer melhor como as Escrituras foram copiadas e guardadas ao longo dos séculos.', 'Salmo 119:89'],
  ['FB11-L06', 'O Texto Massorético é o texto hebraico da Bíblia que foi cuidadosamente copiado e guardado pelos escribas judeus chamados massoretas, entre os séculos VI e X depois de Cristo. Eles criaram regras muito rigorosas para copiar cada letra, garantindo que o texto fosse preservado com muita fidelidade ao longo dos séculos. Quando você lê o Antigo Testamento em português, provavelmente está lendo uma tradução feita a partir desse texto massorético.', 'Isaías 40:8'],
  ['FB10-L14', 'Quando lemos a Bíblia, Deus não nos deixa sozinhos para tentar entender suas palavras. O Espírito Santo age no nosso coração e na nossa mente, como uma luz que ilumina nossa compreensão. Ele nos ajuda a entender o que Deus quer nos dizer através das Escrituras, tornando verdades profundas accessíveis para nós. Por isso, ao estudar a Bíblia, é importante pedir que o Espírito Santo nos ajude a compreender e aplicar o que aprendemos em nossa vida.', 'Joao 14:26'],
  ['FB10-L13', 'A Bíblia foi escrita por mais de 40 autores diferentes, ao longo de aproximadamente 1.500 anos, em três continentes e em línguas distintas. Apesar disso, ela apresenta uma harmonia surpreendente, com uma mensagem coerente do começo ao fim: o plano de Deus para salvar a humanidade. Essa unidade mostra que, por trás dos escritores humanos, havia uma mente divina guiando cada palavra. Assim, podemos confiar que a Bíblia é um livro especial, authored por Deus mesmo através de pessoas comuns.', '2 Timóteo 3:16'],
  ['FB11-L09', 'Os Manuscritos do Mar Morto sao copias muito antigas da Biblia e de outros textos religiosos, encontrados em cavernas perto do Mar Morto, em Israel. Eles foram descobertos entre 1947 e 1956 por beduinos e arqueologos, e tem mais de dois mil anos de idade! Esses manuscritos sao tao importantes porque mostram que a Biblia que temos hoje e muito semelhante aos textos escritos ha sculos atras, provando que a Palavra de Deus foi bem guardada ao longo do tempo.', 'Isaías 40:8'],
  ['FB11-L11', 'Quando os primeiros cristãos copiavam a Bíblia, eles usavam letras grandes chamadas unciais, semelhantes às nossas maiúsculas de hoje. Mais tarde, por volta do século IX, passaram a usar letras menores, chamadas minúsculos. Essas cópias são como cópias de segurança da Palavra de Deus que nos ajudam a ter certeza de que o texto bíblico chegou até nós corretamente, porque muitas cópias diferentes foram comparadas entre si ao longo dos séculos.', '2 Timoteo 3:16'],
  ['FB11-L14', 'O Códice Alexandrino é um dos manuscritos mais importantes da Bíblia. Ele foi escrito no século V em grego e contém quase toda a Bíblia, incluindo o Antigo e o Novo Testamento. Esse manuscrito foi descoberta na cidade de Alexandria, no Egito, e hoje está guardada no Museu Britânico. Ele nos ajuda a entender como a Bíblia foi copiada e preservada ao longo dos séculos.', '2 Timóteo 3:16'],
  ['FB11-L13', 'O Códice Vaticano é um dos manuscritos mais antigos e importantes da Bíblia. Ele foi copiado no século IV em grego e guardado na Biblioteca Vaticana, em Roma. Esse manuscrito é muito valioso porque ajuda os estudiosos a comparar o texto bíblico que temos hoje com o que foi escrito há quase dois mil anos, mostrando que a Bíblia foi bem preservada ao longo dos séculos.', '2 Timóteo 3:16'],
  ['FB11-L10', 'Os papiros são fragmentos muito antigos escritos em um material feito de uma planta chamada papiro, que os antigos utilizavam para escrever. Muitos desses papiros contêm pedaços dos livros do Novo Testamento e foram descobertos em lugares como o Egito, onde o clima seco ajudou a conservá-los por séculos. Esses documentos são provas importantíssimas de que as palavras da Bíblia que temos hoje chegaram até nós com muita fidelidade, porque os estudiosos podem comparar os textos antigos com os que usamos atualmente. Graças a Deus por ter preservado a sua Palavra ao longo de tantos anos por meio desses manuscritos preciosos!', 'Isaías 40:8'],
  ['FB11-L16', 'Quando os escribas copiavam a Bíblia à mão, ao longo de séculos e séculos, pequenos erros podiam acontecer. Às vezes um copista trocava uma letra, às vezes um leitor acrescentava uma explicação na margem que depois era copiada como se fosse parte do texto. Por isso hoje temos milhares de cópias antigas da Bíblia, e nelas encontramos pequenas diferenças entre si. Isso não significa que a mensagem de Deus foi perdida, mas sim que precisamos de cuidado e sabedoria para descobrir qual era o texto original.', 'Salmos 119:160'],
  ['FB11-L17', 'Deus prometeu que a sua Palavra jamais seria esquecida ou alterada. Ao longo de milhares de anos, homens dedicados copiaram as Escrituras com muito cuidado, verificando cada detalhe para garantir que o texto chegasse até nós exatinho como foi inspirado. Esses manuscritos antigos, encontrados em cavernas e bibliotecas, mostram que Deus velou pelo texto sagrado. Hoje podemos confiar que a Bíblia que temos nas mãos é a mesma mensagem que Deus quis nos dar.', 'Isaías 40:8'],
  ['FB11-L15', 'Os escribas eram estudiosos judeus dedicados a copiar os textos sagrados com muito cuidado e respeito. Eles criavam regras especiais para garantir que cada palavra fosse copiada corretamente, contando letras e usando símbolos para não errar. Graças a esse trabalho fiel e detalhado, Deus preservou a Sua Palavra ao longo de milhares de anos. É impressionante pensar que Deus confiou a homens comuns a missão de guardar e transmitir as Escrituras até nós!', '2 Timoteo 3:16'],
  ['FB12-L04', 'A paráfrase biblica e uma forma especial de traduzir a Biblia. Em vez de traduzir palavra por palavra, ela tenta dizer a mesma mensagem usando palavras mais simples e do nosso tempo, como se someone estivesse explicando o texto com outras palavras. Assim, fica mais facil entender o que a Biblia quer dizer no nosso dia a dia.', '2 Corintios 3:6'],
  ['FB12-L05', 'Quando lemos a Bíblia em português, estamos lendo uma tradução. Por trás de toda tradução, existe um texto original escrito em hebraico, aramaico e grego. Deus inspirou esses textos originais, e estudiosos dedicados trabalham com muito cuidado para comparar os manuscritos mais antigos e confiáveis. Assim, podemos ter certeza de que a mensagem de Deus chega até nós com fidelidade.', 'Isaías 40:8'],
  ['FB12-L02', 'A traducao formal e aquela que busca traduzir a Biblia palavra por palavra, o mais proximo possivel do texto original em hebraico e grego. O objetivo e manter a estrutura e as expressoes da linguagem original, mesmo que, as vezes, o texto fique um pouco mais dificil de entender. Esse tipo de traducao e muito importante porque nos ajuda a ver o quanto a Palavra de Deus e fiel e confiavel ao longo dos seculos.', 'Salmos 119:105'],
  ['FB11-L07', 'O Pentateuco Samaritano é uma versão muito antiga dos cinco primeiros livros da Bíblia, escrita em hebraico pelos samaritanos. Os samaritanos são um pequeno grupo religioso que vive perto de Nablus, na Palestina, e eles guardam esse texto há milhares de anos. Os estudiosos comparam esse texto com outros manuscripts antigos para entender melhor como a Bíblia foi transmissionada ao longo dos séculos, verificando se o texto que temos hoje estava bem preservado.', 'Deuteronomio 31:26'],
  ['FB11-L12', 'O Códice Sinaítico é um dos manuscritos mais antigos que possuímos da Bíblia. Foi escrito no século IV e descoberto no Monasterio de Santa Catarina, no Sinai. Imagine que a Bíblia é como uma carta muito especial que foi copiada à mão durante centenas de anos. Com o tempo, as cópias podem ter pequenos erros de transcrição. Por isso, os estudiosos comparam vários manuscritos antigos para descobrir qual era o texto original. O Códice Sinaítico é uma dessas cópias antigas e preciosas que nos ajuda a ter certeza de que o texto bíblico que temos hoje é confiável e verdadeiro, como Deus revelou aos autores sagrados.', '2 Timóteo 3:16'],
  ['FB12-L06', 'A Bíblia Antigo Testamento foi escrita originalmente na língua hebraica, que era a linguagem do povo de Deus no contexto bíblico. Ao longo de muitos séculos, escribas judeus copiaram esses textos com muito cuidado para preservar cada palavra. Quando a Bíblia precisa ser traduzida para outras línguas, os tradutores partem desses textos em hebraico como base. Esse trabalho de tradução é importante para que pessoas de diferentes culturas e idiomas possam ler e compreender a mensagem de Deus.', 'Salmo 119:89'],
  ['FB12-L03', 'A equivalência funcional é uma forma de traduzir a Bíblia que prioriza o significado e o impacto que as palavras tinham para as pessoas originais, em vez de traduzir palavra por palavra. O tradutor busca que o leitor de hoje sinta algo parecido com o que o leitor antigo sentiu ao ouvir aquelas palavras. Por isso, às vezes a tradução muda um pouco a forma das frases, para que o sentido fique claro para nós hoje. É como explicar uma piada: o importante é que você ria, não que repita as palavras exatas.', 'Provérbios 25:11'],
  ['FB12-L10', 'As traduções protestantes da Bíblia em português foram feitas por estudiosos que quiseram colocar a Palavra de Deus numa linguagem que o povo pudesse entender com clareza. Entre as mais conhecidas estão a Almeida Revista e Corrigida, a Almeida Fiel e a Nova Versão Internacional. Cada tradução tem um estilo próprio: algumas seguem mais as palavras originais, outras buscam explicar o sentido para o leitor de hoje. O importante é que todas querem levar a mensagem da Bíblia até nós.', '2 Timóteo 3:16'],
  ['FB12-L12', 'João Ferreira de Almeida foi um tradutor brasileiro que dedicou sua vida para traduzir a Bíblia para a língua portuguesa. Ele viveu em uma época em que a Bíblia era difícil de ser compreendida pelo povo comum, por isso seu trabalho foi muito importante para que todos pudessem ler e entender a Palavra de Deus. Graças ao esforço dele, milhões de pessoas no Brasil e em outros países de língua portuguesa podem ler as Escrituras em sua própria língua. A tradução de Almeida, revisada ao longo dos anos, continua sendo uma das mais usadas e amadas pelos brasileiros até hoje.', 'Salmos 119:105'],
  ['FB12-L08', 'Quando traduzimos a Bíblia para diferentes idiomas e culturas, encontramos desafios porque cada povo tem costumes, expressões e formas de pensar diferentes. Às vezes uma palavra ou expressão de uma cultura não tem um significado igual em outra. Por isso, os tradutores precisam entender bem tanto a cultura original da Bíblia quanto a cultura dos leitores atuais, para que a mensagem de Deus seja compreendida corretamente por todos os povos.', 'Romanos 14:3'],
  ['FB12-L15', 'A Nova Almeida Atualizada, chamada carinhosamente de NAA, é uma traducão da Biblia em português brasileiro feita para ser mais fácil de ler e entender. Ela manteve o estilo da tradicional Tradução Almeida, mas atualizou palavras e expressões que as pessoas tinham dificuldade de compreender. Assim, hoje ela ajuda muitos brasileiros a lerem e estudarem a Palavra de Deus com mais clareza e proximidade da nossa linguagem do dia a dia.', 'Salmos 119:105'],
  ['FB12-L14', 'A Bíblia Almeida Revista e Atualizada, também chamada de ARA, é uma tradução brasileira baseada na Tradução Brasileira de João Ferreira de Almeida. Ela manteve a fidelidade ao texto original hebraico e grego, mas usou uma linguagem mais clara e acessível para os leitores modernos. Isso significa que você pode entender melhor a mensagem de Deus sem perder a precisão da Palavra. É uma das traduções mais usadas nas igrejas evangélicas brasileiras hoje em dia.', 'Salmo 119:105'],
  ['FB12-L16', 'A Nova Versão Internacional, também chamada de NVI, é uma tradução feita com muito cuidado por estudiosos e linguistas para que você possa entender a Palavra de Deus de forma clara e atual. Ela busca ser fiel aos textos originais em hebraico, aramaico e grego, ao mesmo tempo em que usa palavras fáceis de compreender nos dias de hoje. Assim, milhões de pessoas ao redor do mundo conseguem ler e entender a Bíblia com mais facilidade.', 'Salmo 119:130'],
  ['FB12-L18', 'A Bíblia de Jerusalém é uma tradução muito especial feita na França por um grupo de estudiosos que moravam em Jerusalém. Ela é famosa porque traz muitas notas explicativas nas laterais que nos ajudam a entender melhor o que a Bíblia quer dizer. Desde 1948, ela tem ajudado muitas pessoas ao redor do mundo a conhecerem a Palavra de Deus com mais profundidade.', 'Isaías 40:8'],
  ['FB12-L17', 'A Bíblia é o livro mais lido e traduzido do mundo, e existem muitas traduções em português para ajudar pessoas de diferentes idades e contextos a entenderem a Palavra de Deus. Cada tradução busca equilibrar fidelidade aos textos originais com clareza para o leitor moderno. Ter a Bíblia em nossa língua é uma bênção que nos permite conhecer Deus diretamente e crescer na fé todos os dias.', 'Romanos 12:2'],
  ['FB12-L11', 'Existem diferentes traduções da Bíblia em português, e algumas são usadas especialmente pela Igreja Católica. Uma diferença importante é que as traduções católicas incluem livros que os protestantes chamam de apócrifos, como Tobias e Judite. Essas traduções foram feitas para ajudar os Catholics a conhecerem a Palavra de Deus em sua própria língua. O importante é que, independentemente da tradução, todos buscam conhecer melhor Deus através da Sua Palavra.', '2 Timóteo 3:16'],
  ['FB12-L20', 'A Bíblia foi escrita originalmente em hebraico, grego e aramaico. Ao longo dos séculos, ela foi traduzida para muitos idiomas, incluindo o português. Existem traduções que seguem mais de perto as palavras originais e outras que buscam adaptar o texto para a compreensão do leitor moderno. Não existe uma tradução \'certa\' ou \'errada\' — cada uma tem seu valor e propósito. O importante é escolher uma tradução confiável e que te ajude a entender melhor a mensagem de Deus para sua vida.', '2 Timoteo 3:16'],
  ['FB13-L01', 'Hermenêutica é a ciencia que nos ensina a interpretar a Biblia de forma correta e coerente. Assim como um mapa precisa ser lido da forma certa para chegarmos ao destino, as Escrituras tambem precisam ser interpretadas com cuidado, considerando o contexto historico, cultural e tambem o sentido das palavras originais. Quando entendemos a hermeneutica, conseguimos ouvir o que Deus realmente quis dizer atraves dos textos biblicos, evitando误解 e encontrando a mensagem eterna de Deus para nos.', '2 Timoteo 2:15'],
  ['FB13-L04', 'Para entender a Bíblia de forma correta, precisamos primeiro conhecer o contexto em que cada livro foi escrito. Isso significa saber quem escreveu, para quem foi escrito, quando e por que. Assim como quando você recebe uma carta, é importante saber quem a enviou e em que situação, para entender a mensagem. O contexto ajuda-nos a não tirar conclusões erradas sobre o que a Bíblia quer nos ensinar.', 'Atos 8:30-31'],
  ['FB12-L13', 'A Almeida Revista e Corrigida, carinhosamente chamada de ARC, é uma das traduções mais amadas e usadas no Brasil. Ela começou a ser feita pelo pastor João Ferreira de Almeida no século XVII e, ao longo dos anos, passou por revisões para ficar cada vez mais fiel aos textos originais. Hoje, ela é a tradução que está no coração de milhões de brasileiros e está presente em quase todos os lares evangélicos do país. Ter uma boa tradução da Bíblia é muito importante para entendermos melhor a mensagem de Deus.', 'Salmos 119:105'],
  ['FB13-L06', 'Para entender a Bíblia corretamente, precisamos conhecer a cultura do povo bíblico. Assim como nós vivemos em uma cultura diferente, as pessoas da Bíblia viviam em outro tempo e lugar, com costumes, valores e formas de pensar que eram próprios deles. Quando conhecemos esse contexto cultural, as Escrituras ganham um sentido muito mais rico e fiel, porque conseguimos entender o que Deus estava comunicando para aquelas pessoas e como podemos aplicar isso em nossas vidas hoje.', '1 Corintios 9:21'],
  ['FB13-L03', 'Quando lemos a Bíblia, cada versículo não está sozinho - ele faz parte de uma história maior. O contexto imediato é como olhar para as fotos ao lado de uma foto especial: elas nos ajudam a entender melhor o que está acontecendo. Antes de tirar uma lição de um versículo, é muito importante ler o parágrafo inteiro e até o capítulo todo, porque as palavras ganham sentido quando sabemos o que vem antes e depois delas.', 'Atos 10:34'],
  ['FB13-L02', 'Na leitura da Bíblia, precisamos prestar atenção em três coisas importantes: quem escreveu (o autor), o que está escrito (o texto) e quem lê (o leitor). O autor divino ou humano teve uma intenção ao escrever. O texto, inspirado por Deus, tem um significado que podemos descobrir. E nós, como leitores, precisamos nos aproximar da Bíblia com humildade e cuidado para entender a mensagem que Deus quer nos ensinar. Uma boa interpretação respeita o que o texto realmente diz, sem inventar significados que não existem.', '2 Timóteo 3:16'],
  ['FB13-L08', 'Quando lemos a Bíblia, é muito importante lembrarmos que cada texto foi escrito por alguém, em um lugar e tempo específicos, com um propósito tertentu. A intenção do autor nos ajuda a entender a mensagem verdadeira que Deus quer nos ensinar. Isso significa perguntar: Por que esse texto foi escrito? O que o autor queria que as pessoas da época entendessem? Assim, conseguimos interpretar a Palavra de Deus de forma correta e applyinga à nossa vida hoje.', '2 Timoteo 2:15'],
  ['FB12-L19', 'Existem muitas traduções da Bíblia porque os idiomas mudam com o tempo e diferentes tradutores escolhem formas diferentes de expressar o mesmo significado. Comparar traduções nos ajuda a entender melhor o que Deus quis dizer, porque uma tradução pode esclarecer o que outra deixou mais difícil. Assim como um amigo explica uma coisa de jeitos diferentes até você entender, as traduções bíblicas nos ajudam a compreender melhor a mensagem de Deus para nós.', '2 Timóteo 3:16'],
  ['FB13-L10', 'A interpretaçao literal nos ensina a entender a Biblia pelo sentido natural das palavras, como entendemos qualquer outro livro. Isso significa ler o que esta escrito, considerar quem escreveu, para quem e em que época, e buscar o significado que o autor biblico quis transmitir. Quando a Biblia diz \'mão\', geralmente é mão mesmo, e não significa outro simbolismo.', '2 Timoteo 3:16'],
  ['FB13-L11', 'A linguagem figurada usa palavras com sentido diferente do literal para criar imagens na nossa mente e transmitir verdades mais profundas. Na Bíblia, Jesus usou muitas figuras de linguagem, como quando disse que Ele é a videira e nós somos os ramos, querendo mostrar que estamos ligados a Ele para viver e dar frutos. Precisamos ter cuidado para não entender essas figuras de forma rígida, mas perceber o que Deus quer nos ensinar através delas.', 'Joao 15:1'],
  ['FB13-L15', 'Em toda a Bíblia, Deus faz promessas específicas para pessoas e situações concretas. Ao estudar as Escrituras, precisamos distinguir entre essas promessas e os princípios eternos que podemos aplicar hoje. Um princípio é uma verdade geral que Deus quer que sigamos em qualquer época, enquanto uma promessa pode ter condições ou ser destinada a um grupo específico. Entender essa diferença nos ajuda a interpretar e aplicar a Palavra de Deus com sabedoria e fidelidade, sem tirar textos do seu contexto original.', 'Hebreus 6:13-15'],
  ['FB13-L16', 'A expressao \'alianca\' na Biblia significa uma promess a solene feita por Deus com o seu povo. Na Antiga Alianca, Deus fez um acordo com o povo de Israel, baseado na Lei, onde ele promitia ser o deles e eles deveriam obedecer aos seus mandamentos. Na Nova Alianca, selada pelo sangue de Jesus Cristo, Deus offrece salvacao pela graa, escrevendo sua lei no coracao das pessoas e perdoando seus pecados de vez por todas. Compreender essa diferenca e fundamental para interpretar corretamente as Escrituras, pois nem tudo que valia para o povo antigo se aplica da mesma forma ao povo de Deus hoje.', 'Hebreus 8:8-12'],
  ['FB13-L18', 'Quando lemos a Bíblia, precisamos ter cuidado para não entender errado o que Deus quer nos dizer. Erros de interpretação acontecem quando tiramos um versículo do seu contexto, quando lemos com pressa sem pensar no que realmente significa, ou quando queremos que a Bíblia diga o que nós queremos ouvir. Estudar com atenção, orar antes de ler e pedir ajuda de pessoas que conhecem as Escrituras nos protege de compreender mal a Palavra de Deus.', '2 Pedro 1:20'],
  ['FB13-L12', 'A analogia da fé é um princípio que nos ajuda a interpretar a Bíblia de forma segura. Ele diz que, quando encontramos um trecho difícil de entender, devemos comparar com outros trechos claros da Palavra de Deus que falam sobre o mesmo assunto. Assim, as partes claras da Bíblia iluminam as partes mais difíceis, e nunca o contrário. Esse princípio nos protege de tirar conclusões erradas e nos ajuda a entender a mensagem completa de Deus para nós.', 'Hebreus 4:12'],
  ['FB14-L04', 'Quando lemos a Biblia varias vezes, nosso coração e nossa mente vao entendendo cada vez mais. Na primeira leitura podemos entender a historia, na segunda percebemos detalhes que nao vimos antes, e assim por diante. Deus fala conosco atraves da sua Palavra, e quanto mais lemos, mais proximos ficamos dele e mais sabedoria recebemos.', 'Josue 1:8'],
  ['FB14-L06', 'Quando lemos a Bíblia, precisamos entender que cada texto foi escrito em um tempo, lugar e situação específicos, com pessoas e problemas reais. O contexto é como o cenário de uma história: imagine tentar entender um diálogo de um filme sem saber quem são as personagens e o que está acontecendo! Por isso, antes de entender o significado de um versículo, é muito importante conhecer quem o escreveu, para quem, por que motivo e quando. Assim, conseguimos compreender melhor a mensagem que Deus quer nos transmitir através daquele texto.', 'Atos 2:14'],
  ['FB14-L05', 'A Bíblia não é um livro de um só tipo. Ela tem histórias, poemas, cartas, profecias e visões. Cada gênero tem suas próprias regras de leitura. Quando descobrimos que tipo de texto estamos lendo, fica mais fácil entender o que Deus quer nos dizer através dele.', 'Joao 1:1'],
  ['FB14-L02', 'Exegese e quando nos ledores nos aproximamos da Biblia com humildade, deixando que o texto fale por si mesmo e nos ensine o que Deus quer nos dizer. Ja a eisegese acontece quando, sem perceber, nós colocamos nossas ideias no texto e fazemos a Biblia dizer o que queremos ouvir. Como amigos que amam a Deus, devemos sempre buscar entender o que a Palavra realmente ensina, e não fazer dela um espelho das nossas opinioes. Isso nos protege de interpretar a Biblia de forma errada e nos ajuda a crescer na verdade.', 'Atos 17:11'],
  ['FB13-L17', 'Cristo nao esta presente apenas no Novo Testamento. Desde o livro de Genesis, quando Deus prometeu que a semente da mulher pisaria a cabeca da serpente, ate os ultimos profetas, toda a Biblia aponta para Jesus. As historias do Antigo Testamento sao como sombras e figuras que se cumpriram em Cristo, como a arca de Noe que nos salva do juizo, o cordeiro pascoal que foi sacrificado em nosso lugar, e a maná que sustentou Israel no deserto. Por isso, quando lemos o Antigo Testamento com olhos de fe, descobrimos que Jesus esta presente em cada pagina.', 'Lucas 24:44'],
  ['FB14-L09', 'Os conectivos são palavras que unem ideias no texto bíblico e nos ajudam a entender como o autor construiu seu raciocínio. Quando a Bíblia usa expressões como \'portanto\', \'porque\', \'mas\' ou \'assim\', ela nos mostra a relação entre as ideias - se é causa e consequência, contraste ou explicação. Estudar esses conectivos é como aprender a ler as \'setas de direção\' que guiam o pensamento do escritor sagrado, garantindo que não tiremos conclusões erradas do texto.', 'Romanos 12:2'],
  ['FB14-L13', 'Quando lemos a Biblia, é muito bom saber que existem varias traduções do texto original. Cada traduçao pode usar palavras um pouco diferentes, o que nos ajuda a entender melhor o sentido de um versiculo. Por isso, comparar mais de uma traduçao é como olhar a mesma verdade por varios ângulos, e isso nos faz compreender a mensagem de Deus com mais profundidade e clareza.', 'Salmos 119:105'],
  ['FB14-L11', 'A analise historica nos ajuda a entender como viviam as pessoas na epoca em que a Biblia foi escrita. Assim como nos voce conhece o lugar onde nasceu, os costumes da sua familia e a epoca em que viveu, tambem e importante conhecer esses detalhes para entender melhor o que os textos biblicos queriam dizer naquela época. Quando sabemos como era a vida daquelas pessoas, conseguimos compreender com mais clareza as lies que Deus quer nos ensinar atraves da Sua Palavra.', 'Atos 17:26'],
  ['FB14-L16', 'A ideia central de um texto bíblico é o pensamento principal que o autor quer transmitir. Para identificá-la, pergunte-se: \'Qual é a mensagem mais importante deste trecho?\' e \'Se eu tivesse que resumir tudo em uma frase, o que diria?\'. Descobrir a ideia central nos ajuda a entender o propósito de Deus para nós naquele texto, evitando perder tempo com detalhes que podem nos distrair do ensinamento principal.', '2 Timoteo 3:16'],
  ['FB14-L17', 'Quando lemos um texto da Biblia, precisamos descobrir qual e a mensagem principal que Deus quer nos ensinar por meio daquela passagem. A teologia da passagem e justamente isso: identificar o tema central, o que Deus esta revelando sobre si mesmo e sobre nos. Para encontrar essa mensagem, oramos, lemos com atencao, observamos o contexto e deixamos a Biblia falar antes de tirar conclusoes.', '2Timoteo 3:16'],
  ['FB14-L15', 'Quando estamos estudando a Palavra de Deus, podemos pedir ajuda de estudiosos que escreveram comentarios sobre a Biblia. Esses comentarios sao como um guia amigo que nos ajuda a entender melhor o que a Escritura quer dizer. Consultar comentarios nao substitui a leitura direta da Biblia, mas nos ajuda a entender contextos historicos, palavras dificeis e mensagens que talvez nao perceberiamos sozinhos. Assim como um professor ajuda um aluno, os comentarios nos auxiliam a crescer no conhecimento da verdade biblica.', '2 Timoteo 3:16-17'],
  ['FB14-L14', 'Quando lemos a Bíblia, encontramos palavras que podem ter significados diferentes em grego ou hebraico, as línguas originais do texto sagrado. Os dicionários bíblicos nos ajudam a descobrir esses significados originais, como se fossemos abrir uma janela para o que o autor sagrado realmente quis dizer. Assim, ao consultar um dicionário, entendemos melhor a mensagem de Deus para nós hoje.', '2 Timoteo 3:16'],
  ['FB14-L18', 'Aplicar a Palavra de Deus na nossa vida e muito importante, mas precisamos fazer isso com responsabilidade. Isso significa que nao devemos pegar um texto biblico e usar de qualquer jeito para justificar qualquer coisa. Precisamos entender o sentido real da Escritura, considerar o contexto em que foi escrita e pedir a Deus que nos ajude a aplicar a verdade de forma que glorifique a Ele e abenoe nossa vida e a vida dos outros.', '2 Timoteo 2:15'],
  ['FB14-L12', 'A análise cultural é uma ferramenta muito importante para entendermos a Bíblia. Ela nos ajuda a conhecer os costumes, hábitos e valores das pessoas que viviam na época em que a Bíblia foi escrita. Quando entendemos o contexto cultural, conseguimos compreender melhor as mensagens de Deus para nós hoje. Por exemplo, saber que na cultura antiga a hospitalidade era um valor muito importante nos ajuda a entender por que Jesus ensinou sobre acolher bem as pessoas.', '1 Coríntios 9:19-23'],
  ['FB15-L03', 'Quando copistas escribiam os manuscritos biblicos, pequenas diferencas podiam aparecer entre as copias. Essas diferencas sao chamadas variantes textuais. Existem varios tipos: quando uma palavra e trocada por outra semelhante, e variante lexical; quando a ordem das palavras muda, e variante de ordem; quando palavras sao tiradas ou acrescidas no texto, sao variantes de omissao ou adicao. A boa noticia e que os estudiosos tem ferramentas para identificar qual leitura esta mais proxima do texto original. Deus preservou a sua palavra ao longo dos seculos!', 'Salmo 119:89'],
  ['FB15-L06', 'Na crítica textual bíblica, a evidência externa são todos os sinais que encontramos FORA dos próprios textos, como a idade dos manuscritos, de onde eles vieram, como eram usados pelas antigas igrejas e se os pais da igreja citavam aquela leitura. Quando um texto é muito antigo, foi copiado em lugares diferentes e muitos escritores antigos o usavam, isso nos dá mais segurança de que aquela é provavelmente a leitura original. Os estudiosos comparam essas informações todas para decidir qual texto tem mais chances de ser o que o autor escreveu primeiro.', 'Salmos 119:89'],
  ['FB15-L07', 'Na crítica textual, quando comparamos os manuscritos do Novo Testamento, precisamos também olhar para dentro do próprio texto para descobrir qual leitura é mais antiga e confiável. Isso é o que chamamos de evidência interna. Ela nos ajuda a entender coisas como: qual palavra ou frase faz mais sentido no contexto? O que o autor provavelmente queria dizer? Como os escribas geralmente erravam? Essas perguntas nos guiam a avaliar qual variante textual se parece mais com o texto original escrito pelos autores sagrados, complementa o que aprendemos sobre a evidência externa.', '2 Timoteo 3:16'],
  ['FB15-L05', 'Quando os escribas antigos copiavam os textos bíblicos à mão, às vezes faziam alterações de propósito, não por engano. Eles podiam querer deixar um ensinamento mais claro, harmonizar relatos semelhantes ou corrigir o que achavam que estava errado. Essas mudanças intencionais são estudadas na crítica textual para entender melhor como a Bíblia chegou até nós.', 'Salmos 12:6-7'],
  ['FB14-L19', 'Uma exposicao biblica e uma explicacao detalhada e organizada de um trecho das Escrituras. Ela e feita quando estudamos o texto com cuidado, entendendo o que ele significava na epoca em que foi escrito e depois aplicamos essa verdade para os dias de hoje. Para fazer uma boa exposicao, precisamos da oracao, do estudo honesto da Palavra e da dependencia do Espirito Santo para nos guiar na compreensao correta da mensagem de Deus.', '2 Timoteo 3:16-17'],
  ['FB15-L11', 'Texto majoritário é uma abordagem dentro da crítica textual que acredita que o texto bíblico original foi preservado não necessariamente nos manuscritos mais antigos, mas naquele que aparece na grande maioria dos manuscritos. Pense assim: quando muitas cópias diferentes concordam com algo, é mais difícil que todas estejam erradas ao mesmo tempo. Os estudiosos que seguem esse método analisam milhares de manuscritos gregos e consideram que o texto mais confiável é aquele que tem o maior número de testemunhos a seu favor.', 'Salmos 12:6-7'],
  ['FB15-L01', 'A crítica textual é a área da teologia que estuda como os textos bíblicos foram copiados e transmitidos ao longo dos séculos. Os estudiosos comparam diferentes manuscritos antigos para descobrir qual era a mensagem original dos autores sagrados. Assim, mesmo depois de milhares de anos, podemos ter confiança de que a Bíblia que lemos hoje é fiel ao que Deus quis nos ensinar.', 'Salmos 12:6-7'],
  ['FB15-L12', 'O Texto Recebido é o conjunto de manuscritos que foram usados ao longo da história para produzir as primeiras traduções da Bíblia em português e outras línguas importantes. Ele representa a tradição textual que a Igreja recebeu e utilizou por muitos séculos, sendo a base das traduções tradicionais. Esse texto foi impresso pela primeira vez no século dezesseis e serve como referência importante para entendermos como a Palavra de Deus foi preservada ao longo dos tempos.', '2 Timóteo 3:16'],
  ['FB15-L08', 'A crítica textual estuda os manuscritos antigos da Bíblia para entender quais cópias são mais antigas e confiáveis. Quanto mais antigo é um manuscrito, mais próximo ele está do texto original escrito pelos autores bíblicos. Os estudiosos usam manuscritos muito antigos, como os Manuscritos do Mar Morto e o Código Sinaítico, para comparar e verificar se o texto da Bíblia que temos hoje é fiel ao que foi originalmente escrito. Isso nos dá confiança de que Deus preservou a sua Palavra ao longo dos séculos.', 'Isaías 40:8'],
  ['FB15-L15', 'Jesus nos ensina que Deus é cheio de amor e compaixão para com quem se arrepende de seus pecados. Quando os religiosos trouxeram aquela mulher para ser julgada, Jesus demonstrou uma sabedoria extraordinária: Ele não fechou os olhos para o pecado, mas também não permitiu que ela fosse apedrejada. O Senhor nos dá o exemplo perfeito de como tratar pessoas que falharam: com misericórdia, mas com um convite claro para uma vida nova, sem repetir os mesmos erros.', 'Joao 8:11'],
  ['FB15-L17', 'Quando copistas antigos escribiam os textos bíblicos à mão, às vezes cometiam pequenos erros. Esses erros criaram diferenças entre os manuscritos que existem até hoje. Tradutores modernos estudam esses manuscritos para escolher qual texto ficou mais próximo do original. Por isso, algumas versões da Bíblia podem parecer diferentes em detalhes, mas o sentido geral da mensagem de Deus continua o mesmo.', 'Salmos 119:105'],
  ['FB15-L14', 'O Evangelho de Marcos termina de forma diferente em varios manuscritos antigos. Em alguns, apos o versiculo 8, ha uma continuacao com mais versiculos que contam a ressurreicao e as aparicoes de Jesus. Os estudiosos chamam isso de \'final longo de Marcos\'. Isso acontece porque, la atras, os copistas decidiam o que incluir ou nao ao copiar os textos biblicos, e nem todos faziam a mesma escolha. Esse tipo de diferenca nos ajuda a entender como a Biblia chegou ate nos e como os especialistas verificam cada palavra.', 'Marcos 16:15-16'],
  ['FB16-L01', 'O alfabeto hebraico e o conjunto de letras que Deus deu ao povo de Israel para que pudesse registrar as suas palavras. Diferente do nosso alfabeto, ele e formado por vinte e duas letras, e cada uma delas carrega um significado profundo na linguagem sagrada. Quando oramos ou lemos textos biblicos em hebraico, estamos tocando uma tradicao que comecou ha milhares de anos.', 'Deuteronomio 31:9'],
  ['FB15-L16', 'OComma Johanneum e uma discussao sobre um trecho da Biblia, mais precisamente em Primeira Joao, capitulo cinco, versiculos sete e oito, onde alguns manuscritos antigos incluem a expressao \'tres sao os que testificam no ceu\' enquanto outros manuscritos nao trazem essas palavras. Esse tipo de variacao e comum no estudo da critica textual biblica, pois os copistas, ao longo dos seculos, copiavam os textos a mao e, as vezes, faziam anotacoes nas margens que podiam ser incorporadas ao texto por copistas posteriores. A historia da fe catolica e protestante reconhece que a maioria dos manuscritos mais antigos e confiaveis NAO contem esse trecho, mesmo assim, essa passagem se tornou muito conhecida e e usada ate hoje na defesa da doutrina da Trindade.', '1 Joao 5:7-8'],
  ['FB16-L03', 'O alfabeto hebraico da Biblia e formado por 22 letras, e cada uma delas e uma consoante. Isso e diferente do nosso alfabeto portugues, que tem consoantes e vogais misturadas. No hebraico biblico original, as vogais nao eram escritas com simbolos especiais; elas ficavam \'escondidas\' dentro das palavras. Por isso, quando estudamos hebraico, precisamos aprender primeiro essas 22 consoantes para poder ler e entender as palavras da Biblia em sua lingua original.', 'Salmos 119:105'],
  ['FB16-L04', 'Quando os escribas hebreus escreveram a Bíblia, eles usaram apenas consoantes, sem nenhuma marcação para as vogais. Muitos anos depois, um grupo muito cuidadoso chamado massoretas, que amava muito as Escrituras, criou um sistema especial de pontinhos e tracinhos ao redor das letras para mostrar como cada palavra devia ser pronunciada. Esse sistema de vogais é muito importante porque ele nos ajuda, até hoje, a ler e pronunciar as palavras hebraicas da Bíblia da forma correta, como Deus quis que fossem lidas.', 'Isaías 40:8'],
  ['FB16-L06', 'No hebraico bíblico, a maioria das palavras é formada a partir de raízes formadas por três letras chamadas consoantes-mãe. Essas raízes são como sementes que, ao receber vogais e prefixos ou sufixos, criam palavras com significados diferentes. Por exemplo, a raiz k-t-v (escrever) pode virar \'miktab\' (escritório) ou \'katub\' (escrito). Entender esse sistema ajuda muito a compreender como Deus estruturou Sua Palavra.', 'Isaías 55:11'],
  ['FB15-L18', 'A critica textual estuda as pequenas diferencas que existem entre as copias antigas dos textos biblicos. Ao longo dos seculos, copistas escreveram manuscritos a mao e, as vezes, cometeram pequenos erros ou fizeram pequenas mudancas. Os estudiosos comparam esses manuscritos para descobrir qual era o texto original. A boa noticia e que nenhuma dessas variacoes afeta as verdades centrais do evangelho e o plano de salvacao de Deus.', 'Joao 10:35'],
  ['FB16-L07', 'No hebraico biblico, os substantivos sao palavras que dao nome aos seres, objetos e lugares. Eles tem dois generos: masculino e feminino, que mudam a forma da palavra. A maioria dos substantivos femininos termina com a letra He no final. Reconhecer se um substantivo e masculino ou feminino e essencial para entender a gramatica hebraica.', 'Genesis 2:23'],
  ['FB16-L11', 'As preposicoes sao palavras que mostram a relacao entre as outras palavras na frase. Em hebraico biblico, existem preposicoes bem pequenas, como o \'ב\' que significa \'em\' ou \'com\', o \'ל\' que significa \'para\' ou \'a\', e o \'מ\' que significa \'de\' ou \'desde\'. Quando voce ve essas letras grudadas em uma palavra, elas estao funcionando como preposicoes. Assim como em portugues dizemos \'a casa DE Pedro\', em hebraico a mesma ideia aparece com a preposicao \'min\' ligada a palavra.', 'Genesis 1:1'],
  ['FB16-L13', 'Os verbos em hebraico sao formed by a raiz de tres letras chamadas \'shoresh\' (raiz), que recebe prefixos, sufixos e vogais internas para formar diferentes significado. Existem sete principais \'binyanim\' (padroes verbais) que indicam se a acao e ativa, passiva ou reflexiva. Essa estrutura e incrivelmente logica e nos ajuda a entender como os autores biblicos expressavam acoes e estados com precisao. Quando aprendemos sobre os verbos hebraicos, ganhamos uma chave poderosa para compreender a mensagem original da Biblia.', 'Salmos 119:105'],
  ['FB16-L12', 'No hebraico bíblico, quando queremos mostrar que algo pertence a alguém ou está conectado de forma bem próxima com outra coisa, usamos uma construção especial. O primeiro substantivo fica em um \'estado construto\', como se fosse um imã que puxa o segundo substantivo para perto. O segundo substantivo fica no \'estado absoluto\' e funciona quase como uma resposta: o construto faz a pergunta silenciosa e o absoluto responde. Por exemplo, em \'a casa de Deus\', a palavra \'casa\' está no estado construto e \'Deus\' no estado absoluto.', 'Genesis 1:1'],
  ['FB16-L05', 'O hebraico bíblico é uma língua linda e antiga, e aprender a pronunciar suas letras e palavras nos ajuda a conectar de forma mais profunda com as Escrituras. O alfabeto hebraico tem 22 letras, e cada uma representa um som. Algumas letras parecem semelhantes, mas têm sons diferentes, como o bet (ב) que pode soar como \'v\' ou como \'b\'. Com prática e paciência, você conseguirá ler palavras simples e até trechos curtos da Bíblia em hebraico, sentindo o calor da língua original em que Deus falou ao seu povo.', 'Salmos 119:105'],
  ['FB16-L14', 'No hebraico bíblico, quase todas as palavras derivam de uma raiz formada por três letras consoantes, chamada raiz trilítera. Essa raiz carrega o significado central, e a partir dela Deus forma diferentes palavras como verbos, substantivos e adjetivos. Por exemplo, as três letras K-T-V estão relacionadas com o ato de escrever, e são a raiz de muitas palavras da Escritura.', 'Joao 1:1'],
];

export function applySeedConteudo(db: SQLiteDatabase): void {
  db.withTransactionSync(() => {
    for (const [id, exp, vers] of CONTEUDO_LICOES) {
      db.runSync(
        'INSERT OR IGNORE INTO licao_conteudo (licao_id, explicacao, versiculo_chave) VALUES (?, ?, ?)',
        [id, exp, vers || null],
      );
    }
  });
}
